INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Đại từ nghi vấn “什么/shénme/”', 'Dùng để hỏi người hoặc sự vật (cái gì, gì).', '你叫什么名字/Nǐ jiào shénme míngzi/ -> Tên bạn là gì? 你买什么？/Nǐ mǎi shénme/ -> Bạn mua gì?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Câu có từ “是 /shì/”', 'Dùng để biểu đạt thuộc tính, danh tính của đối tượng, sự vật, sự việc. Dạng phủ định thêm 不 /bú/ ở phía trước', '我是老师。/Wǒ shì lǎoshī/ -> Tôi là giáo viên. 李月不是老师。/Lǐ Yuè bú shì lǎoshī/ -> Lý Nguyệt không phải là giáo viên');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Trợ từ nghi vấn “吗 /ma/”', 'Đặt ở cuối câu trần thuật để tạo thành câu hỏi nghi vấn (phải không, không?).', '你是美国人吗？/Nǐ shì Měiguó rén ma/ -> Bạn là người Mỹ phải không? . 你是学生吗？/Nǐ shì xuésheng ma/ -> Bạn là học sinh phải không?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Đại từ nghi vấn “哪 /nǎ/”', 'Dùng để hỏi về người hoặc sự vật, thường đi kèm lượng từ.', '你是哪国人？ /Nǐ shì nǎ guó rén/ -> Bạn là người nước nào? 哪本书？Nǎ běn shū? -> Quyển sách nào?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Trợ từ kết cấu “的 /de/”', 'Biểu thị quan hệ sở hữu (của). Có thể lược bỏ khi danh từ theo sau là quan hệ thân thuộc.', '她是我的汉语老师。/Tā shì wǒ de Hànyǔ lǎoshī/ -> Cô ấy là giáo viên tiếng Hán của tôi. 这 是我的书。/Zhè shì wǒ de shū/ -> Đây là sách của tôi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Trợ từ nghi vấn “呢 /ne/”', 'Dùng ở cuối câu để hỏi lại, truy vấn tình huống đã đề cập.', '我喜欢喝咖啡。你呢？/Wǒ xǐhuan hē kāfēi. Nǐ ne/ -> Tôi thích uống cà phê. Còn bạn? 他已经吃过饭了。你呢？/Tā yǐjīng chīguo fàn le. Nǐ ne/ -> Anh ấy ăn rồi. Còn bạn?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Đại từ nghi vấn “几/jǐ/”', 'Dùng để hỏi về số lượng nhỏ (thường dưới 10).', '你有几个汉语老师？ /Nǐ yǒu jǐ ge Hànyǔ lǎoshī/ -> Bạn có mấy giáo viên tiếng Hán? 你女儿几岁了？ /Nǐ nǚ''ér jǐ suì le/ -> Con gái bạn mấy tuổi rồi?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Cách diễn đạt các số dưới 100', 'Các số từ 11 đến 99 trong tiếng Trung được tạo thành theo cấu trúc: (Số hàng chục) + 十 + (Số hàng đơn vị)', '李老师今年 50 岁了。/Lǐ lǎoshī jīnnián wǔshí suì le/ -> Thầy Lí năm nay 50 tuổi rồi. 二十三 /èr shí sān/ -> Hai mươi ba.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Trợ từ “了 /le/ -', 'Dùng ở cuối câu chỉ sự thay đổi, sự xuất hiện của 1 tình huống mới.', '我朋友的女儿今年四岁了。/Wǒ péngyou de nǚ''ér jīnnián sì suì le/ -> Con gái bạn tôi năm nay đã bốn tuổi rồi. 李老师今年50岁了。/Lǐ lǎoshī jīnnián wǔshí suì le/ -> Thầy Lí năm nay đã 50 tuổi rồi.),');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Động từ năng nguyện “会 /huì/”', 'Diễn tả khả năng có được thông qua học hỏi. Dạng phủ định dùng 不会 /bú huì/.', '我会写汉字。 /Wǒ huì xiě Hànzì/ -> Tôi biết viết chữ Hán. 你妈妈会做中国菜吗？/Nǐ māma huì zuò Zhōngguócài ma/ -> Mẹ bạn có biết nấu món Trung Quốc không?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Câu có vị ngữ là tính từ', 'Vị ngữ là tính từ, thường dùng 很 /hěn/ làm phó từ chỉ mức độ. Phủ định dùng 不 /bù/.', '你的汉语很好。/Nǐ de Hànyǔ hěn hǎo/ -> Tiếng Hán của bạn rất tốt. 我妈妈的汉语不好。/Wǒ māma de Hànyǔ bù hǎo/ -> Tiếng Hán của mẹ tôi không tốt.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Đại từ nghi vấn “怎么 /zěnme/”', 'Dùng để hỏi phương thức thực hiện hành động, đặt trước động từ.', '这个汉字怎么读？/Zhège Hànzì zěnme dú/ -> Chữ Hán này đọc như thế nào? 你怎么去饭店？/Nǐ zěnme qù fàn diàn/ -> Bạn đi đến nhà hàng bằng cách nào?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Diễn tả ngày tháng', 'Diễn tả tháng, ngày/thứ, thứ tự từ lớn đến nhỏ (năm -> tháng > ngày/thứ).', '9 月 1 号, 星期三。/Jiǔ yuè yī hào, xīngqī sān/ -> Ngày 1 tháng 9, thứ Tư 8 月 31 号, 星期二。 /Bā yuè sān shí yī hào, xīngqī èr/ -> Ngày 31 tháng 8, thứ Ba');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Câu có vị ngữ là danh từ', 'Vị ngữ là danh từ hoặc cụm danh từ (thường diễn tả tuổi tác, thời gian).', '今天 9 月 1 号。/Jīntiān jiǔ yuè yī hào/ -> Hôm nay là ngày 1 tháng 9. 我的汉语老师 33 岁。/Wǒ de Hànyǔ lǎoshī sān shí sān suì/ -> Giáo viên tiếng Hán của tôi 33 tuổi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Cấu trúc liên động từ', 'Hành động thứ nhất biểu thị phương thức hoặc mục đích của hành động thứ hai. Cả hai hành động đều do cùng một chủ thể thực hiện.', '我去图书馆看书。 /Wǒ qù túshūguǎn kàn shū/ Tôi đi thư viện đọc sách. 妈妈上街买菜。 /Māma shàng jiē mǎi cài/ Mẹ ra chợ mua thức ăn.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Động từ năng nguyện “想 /xiǎng/”', 'Biểu thị mong muốn hoặc dự định (muốn).', '我想喝茶。 /Wǒ xiǎng hē chá/ Tôi muốn uống trà. . 明天我想去学校看书。/Míngtiān wǒ xiǎng qù xuéxiào kàn shū/ Ngày mai tôi muốn đến trường đọc sách.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Đại từ nghi vấn “多少 /duōshao/', 'Dùng để hỏi số lượng từ 10 trở lên, hoặc hỏi giá cả.', '你们学校有多少个学生？ /Nǐmen xuéxiào yǒu duōshao ge xuésheng/Trường các bạn có bao nhiêu học sinh? 这个杯子多少钱？ /Zhège bēizi duōshao qián/ Cái cốc này bao nhiêu tiền?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Lượng từ “个/gè” “口/ kǒu/”', '个 /gè/ Lượng từ phổ biến nhất, dùng cho hầu hết danh từ chỉ người, sự vật, đồ vật. Dùng khi không biết rõ lượng từ chuyên biệt. 口 /kǒu/ Lượng từ dùng cho số thành viên trong gia đình.', '一个老师 /yí gè lǎoshī/ một giáo viên 三个苹果 /sān gè píngguǒ/ ba quả táo 我家有四口人 /Wǒ jiā yǒu sì kǒu rén/ Nhà tôi có bốn người 我们家三口人 /Wǒmen jiā sān kǒu rén/ Gia đình tôi có ba người');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Động từ “在 /zài/”', 'Dùng để nói ai đó/cái gì đang ở đâu.', '我朋友在学校。/Wǒ péngyou zài xuéxiào/ Bạn tôi ở trường. 小狗在椅子下面。/Xiǎogǒu zài yǐzi xiàmiàn/ Con chó nhỏ ở dưới ghế.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Đại từ nghi vấn “哪儿/nǎr/', 'Dùng để hỏi về vị trí của người hoặc vật (ở đâu).', '你的杯子在哪儿？/Nǐ de bēizi zài nǎr/ Cái cốc của bạn ở đâu? 你的中国朋友在哪儿？/Nǐ de péngyou zài nǎr/ Bạn của bạn ở đâu?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Giới từ “在 /zài/', 'Dẫn xuất từ động từ "在", dùng để chỉ địa điểm nơi xảy ra hành động.', '他们在学校工作。 /Tāmen zài xuéxiào gōngzuò/ Họ làm việc ở trường. 我在朋友家喝茶。 /Wǒ zài péngyou jiā hē chá/ Tôi uống trà ở nhà bạn.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Trợ từ nghi vấn “呢 /ne/”', 'Dùng ở cuối câu, hỏi lại về vị trí hoặc truy vấn về người/vật.', '我的小猫呢？ /Wǒ de xiǎomāo ne/ Con mèo nhỏ của tôi đâu? 他在哪儿呢？/Tā zài nǎr ne/ Anh ấy ở đâu vậy?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Câu có từ “有 /yǒu/”', 'Biểu thị sự tồn tại hoặc sự sở hữu (có). Phủ định dùng 没 (有).', '我的家乡有一条小河。/Wǒ de jiāxiāng yǒu yì tiáo xiǎo hé/ -> Quê tôi có một con sông nhỏ. 房间里没有人。 /Fángjiān lǐ méi yǒu rén/ -> Trong phòng không có ai.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Liên từ “和 /hé/', 'Dùng để nối hai hoặc nhiều thành phần giống nhau (danh từ, đại từ, cụm danh từ) trong câu.', '哥哥和姐姐都在家。/Gēge hé jiějie dōu zài jiā/ Anh trai và chị gái đều ở nhà. 我们学习了生词、语法和课文。 /Wǒmen xuéxí le shēngcí hé yǔfǎ/ Chúng tôi đã học từ mới và ngữ pháp.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Động từ năng nguyện “能/néng/”', 'Dùng để biểu thị khả năng, năng lực hoặc sự cho phép (có thể).', '我能说汉语。/Wǒ néng shuō Hànyǔ./ → Tôi có thể nói tiếng Trung. 这里能停车吗？/Zhèlǐ néng tíngchē ma?/ → Ở đây có được đỗ xe không?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', '“请 /qǐng/', 'Dùng để diễn tả lời đề nghị, yêu cầu lịch sự, mềm mỏng (mời).', '请坐。/Qǐng zuò/ Mời ngồi. . 请喝茶。/Qǐng hē chá/ Mời uống trà.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Cách diễn tả thời gian', 'Diễn tả theo thứ tự từ lớn đến nhỏ: Số giờ + 点 /diǎn/ + Số phút + 分 /fēn/', '现在 八点十八分。/Xiànzài bā diǎn shíbā fēn/ Bây giờ là 8 giờ 18 phút. 三点 十五 分 /sān diǎn shíwǔ fēn/ 3 giờ 15 phút');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Từ chỉ thời gian làm trạng ngữ', 'Từ/cụm từ chỉ thời điểm, khoảng thời gian (như: 今 天，每天，八点，去年，...), đứng trong câu để bổ nghĩa cho toàn bộ hành động, trả lời câu hỏi "Khi nào?".', '明天我们去公园。/Míngtiān wǒmen qù gōngyuán./ → Ngày mai chúng tôi đi công viên. 晚上八点她看电视。/Wǎnshang bā diǎn tā kàn diànshì./ → Lúc 8 giờ tối cô ấy xem TV.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Danh từ “前 /qián/”', 'Biểu thị một khoảng thời gian trước thời điểm hiện tại/được đề cập.', '三天前 /sān tiān qián/ -> Ba ngày trước. 我以前住在北京。/Wǒ yǐqián zhù zài Běijīng/ → Trước đây tôi sống ở Bắc Kinh.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Đại từ nghi vấn “怎么样 /zěnmeyàng/', 'Dùng để hỏi về tính chất, trạng thái, ý kiến hoặc đề xuất.', '这部电影怎么样？/Zhè bù diànyǐng zěnmeyàng?/ → Bộ phim này như thế nào? (Hay/dở ra sao?) 我们晚上吃火锅，怎么样？ /Wǒmen wǎnshang chī huǒguō, zěnmeyàng?/ → Tối nay chúng ta ăn lẩu, thấy sao?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Câu có vị ngữ là kết cấu chủ-vị', 'Vị ngữ là một cụm từ có cấu trúc chủ-vị: [Chủ ngữ 1] + [Vị ngữ (Chủ ngữ 2 + Động từ 2)]', '这本书 内容很有趣。/Zhè běn shū nèiróng hěn yǒuqù/ Cuốn sách này nội dung rất thú vị. 这家餐厅 价格很贵。/Zhè jiā cāntīng jiàgé hěn guì/ Nhà hàng này giá cả rất đắt.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Phó từ chỉ mức độ “太 /tài/', 'Diễn tả mức độ quá cao, thường đi kèm 了 (le). Phủ định dùng 不太.', '太热了。/Tài rè le/ Nóng quá rồi. 天气太冷了。/Tiānqì tài lěng le/ Thời tiết lạnh quá rồi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Động từ năng nguyện “会 /huì/', 'Dùng để diễn tả khả năng xảy ra của một tình huống (dự đoán).', '明天会下雨。/Míngtiān huì xiàyǔ./ → Ngày mai sẽ mưa. 他应该会同意。/Tā yīnggāi huì tóngyì./ → Anh ấy chắc sẽ đồng ý.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Thán từ “喂 /wèi/', 'Dùng để gọi, thu hút sự chú ý hoặc bắt đầu cuộc trò chuyện, đặc biệt là qua điện thoại.', '喂，李老师在家吗？/Wèi, Lǐ lǎoshī zài jiā ma?/ A lô, thầy Lý có ở nhà không? 喂，你是张小姐吗？/Wèi, nǐ shì Zhāng xiǎojiě ma/ A lô, cô là cô Trương phải không?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Cấu trúc “在 ……呢” (zài...ne)', 'Biểu thị hành động đang diễn ra (đang).', '你在做什么呢？/Nǐ zài zuò shénme ne/ Bạn đang làm gì vậy? 我在看书呢。/Wǒ zài kàn shū ne/ Tôi đang đọc sách.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Cách đọc số điện thoại', 'Đọc từng chữ số một, tuần tự từ trái sang phải. Số "1" đọc là /yāo/.', '82304156 /bā èr sān líng sì yāo wǔ liù/ 13851897623 /yāo sān bā wǔ yāo bā jiǔ qī liù èr sān/');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Trợ từ ngữ khí “吧 /ba/', 'Đề nghị, khuyên bảo, mệnh lệnh.', '我们走吧。/Wǒmen zǒu ba. / → Mình đi thôi. 她在工作呢，你下午打吧。 /Tā zài gōngzuò ne, nǐ xiàwǔ dǎ ba/ Cô ấy đang làm việc, chiều bạn gọi điện đi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Trợ từ 了/le/', 'Dùng sau động từ/tính từ để biểu thị sự việc đã xảy ra hay hoàn thành.', '她去商店了。/Tā qù shāngdiàn le/ Cô ấy đã đi cửa hàng rồi. 我买了一点儿苹果。 /Wǒ mǎi le yì diǎnr píngguǒ/ Tôi đã mua một ít táo.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Danh từ 后 /hòu/', 'Biểu thị một khoảng thời gian sau thời điểm được đề cập (sau).', '五点四十分钟后。/Wǔ diǎn sì shí fēnzhōng hòu/ Sau 5 giờ 40 phút 五 点后。/Wǔ diǎn hòu/ Sau 5 giờ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Trợ từ ngữ khí 啊 /a/', 'Trợ từ ngữ khí 啊 /a/ (có thể biến âm thành /ya/, /wa/, /na/... tùy âm tiết trước nó) khi đặt cuối câu trần thuật có tác dụng làm mềm mại, thân mật, nhấn mạnh hoặc bày tỏ cảm xúc', '小心啊！/Xiǎoxīn a/ Cẩn thận đấy! 快点儿啊，要迟到了！/Kuài diǎnr a, yào chídào le!/ Nhanh lên nào, sắp muộn rồi!');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Phó từ 都 /dōu/', 'Biểu thị sự bao gồm hoặc tổng hợp (đều, tất cả).', '他们都喜欢看电视。 /Tāmen dōu xǐhuan kàn diànshì/ Họ đều thích xem TV. 我们都是坐出租车来的。/Wǒmen dōu shì zuò chūzūchē lái de/ Chúng tôi đều là đi taxi đến.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Cấu trúc “是 ……的”', 'Nhấn mạnh thời gian, địa điểm, hoặc cách thức xảy ra sự việc đã biết.', '我们是坐出租车来的。 /Wǒmen shì zuò chūzūchē lái de/ Chúng tôi đến bằng taxi. 你是什么时候开始学汉语的？ /Nǐ shì shénme shíhou kāishǐ xué Hànyǔ de/ Bạn là bắt đầu học tiếng Hán từ khi nào?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Cách diễn tả ngày tháng', 'Diễn tả đầy đủ năm, tháng, ngày, thứ, theo thứ tự từ lớn đến nhỏ.', '今天是 2025 年 1 月 5 号。 Jīntiān shì èr líng èr wǔ nián yī yuè wǔ hào. → Hôm nay là ngày 5 tháng 1 năm 2025. 明天是 2024 年 12 月 18 号，星期三。 Míngtiān shì èr líng èr sì nián shí''èr yuè shíbā hào, xīngqīsān. → Ngày mai là thứ Tư, ngày 18 tháng 12 năm 2024.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Số lượng và định lượng', '- Các số dưới 100 - Đại từ nghi vấn “几 /jǐ/ - Đại từ nghi vấn “多少 /duōshao/ - Cách đọc số điện thoại', 'Đề thi thường kiểm tra trực tiếp khả năng nghe và phân biệt số lượng, tuổi tác, giá cả, và các con số phức tạp hơn (như số điện thoại) qua các tùy chọn trắc nghiệm.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Hỏi đáp cơ bản (Nghi vấn)', '- Đại từ nghi vấn “什么 /shénme/” - Trợ từ nghi vấn “吗 /ma/” - Đại từ nghi vấn “哪 /nǎ/” - Đại từ nghi vấn “哪儿 /nǎr/” - Đại từ nghi vấn “怎么样 /zěnmeyàng/”', 'Các câu hỏi nghi vấn là cấu trúc cơ bản nhất của mọi bài kiểm tra ngôn ngữ. Đặc biệt là hỏi về danh tính, địa điểm, và tình trạng/trạng thái (thời tiết, sức khỏe).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Hành động và trạng thái', '. Động từ/Giới từ “在 /zài/” . Cấu trúc “在……呢 /zài...ne/” Trợ từ “了 /le/”', 'Kiểm tra khả năng phân biệt giữa hành động đang diễn ra (在……呢) và hành động đã hoàn thành (了). Đây là hai khái niệm thì/trạng thái hành động quan trọng nhất ở cấp độ HSK 1.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 1', 'Động từ năng nguyện', 'Động từ năng nguyện “想 /xiǎng/ Động từ năng nguyện “会 /huì/”', '“想 (muốn) và 会 (biết/sẽ) là hai động từ năng nguyện thiết yếu giúp người học diễn đạt ý định, khả năng và dự đoán. Chúng thường xuyên xuất hiện trong các tình huống hội thoại cơ bản, đóng vai trò quan trọng trong việc hình thành câu và thiết lập bối cảnh giao tiếp.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Trợ động từ "要 /yào/”', 'Khi là trợ động từ, 要 đứng trước động từ chính và diễn đạt ý chí, nguyện vọng hoặc sự cần thiết.', '王方要学习英语。 /Wáng Fāng yào xuéxí Yīngyǔ/ Vương Phương muốn học tiếng Anh. 我 要 吃米饭。 /Wǒ yào chī mǐfàn/ Tôi muốn ăn cơm.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Phó từ chỉ mức độ "最 /zuì/', '最 có nghĩa là "nhất", dùng để biểu thị mức độ cao nhất trong phạm vi so sánh. Nó tương đương với hậu tố "-est" trong tiếng Anh (tallest, biggest) hoặc từ "most".', '大卫的汉语最好。 /Dàwèi de Hànyǔ zuì hǎo/ Tiếng Hán của Đại Vệ là tốt nhất. 我最喜欢吃米饭。/Wǒ zuì xǐhuān chī mǐfàn/ Tôi thích ăn cơm nhất.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Cách diễn tả số lượng "几 /jǐ/', '几 dùng để hỏi về số lượng ít, ước chừng dưới 10. Cấu trúc cơ bản: 几 + Lượng từ + Danh từ?', '这里住着几个人？ /Zhèlǐ zhù zhe jǐ gè rén/ Ở đây có mấy người ở? 你学中文学了几年了？ /Nǐ xué Zhōngwén xué le jǐ nián le/ Bạn học tiếng Trung được mấy năm rồi?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Câu hỏi với "是 不是..." /shì.bú shì../', 'Nếu đưa ra phỏng đoán về một sự việc hoặc tình huống và muốn xác minh thêm, có thể dùng cấu trúc câu hỏi này. "是不 是..." thường dùng ở phía trước vị ngữ, nhưng cũng có thể dùng ở đầu hoặc cuối câu.', '你很少生病，是不是喜欢运动？ /Nǐ hěn shǎo shēngbìng, shì bù shì xǐhuan yùndòng/ Cậu rất ít khi ốm, có phải là thích vận động không? 是不是明天爸爸休息? /Shì bù shì míngtiān bàba xiūxi/ Có phải ngày mai bố nghỉ không?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Đại từ "每 /měi/”', '每 thường không đứng một mình. Nó luôn đi kèm với một danh từ, lượng từ hoặc từ chỉ thời gian để tạo thành một cụm để chỉ tất cả các thành viên trong tập thể hoặc nhóm. Ví dụ: hằng ngày, mỗi năm, mỗi tháng, mỗi tuần.', '山姆每年都去中国旅游。 /Shānmǔ měi nián dōu qù Zhōngguó lǚyóu/ Sam mỗi năm đều đi du lịch Trung Quốc. . 我每天六点 起床工作 吗？ /Wǒ měi tiān liù diǎn qǐchuáng gōngzuò ma/ Tôi có phải mỗi ngày 6 giờ thức dậy làm việc không?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Đại từ nghi vấn " 多 /duō/”', '多 được dùng để hỏi về độ cao, chiều dài, tuổi tác, khoảng cách, thời gian, giá cả... - tức là những thứ có thể đo lường được bằng con số.', '你多大？/Nǐ duō dà/ Bạn bao nhiêu tuổi? 他儿子多高？ /Tā érzi duō gāo/ Con trai anh ấy cao bao nhiêu?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Cụm từ có "的 /de/”', 'Đại từ, tính từ, động từ kết hợp với "的" để tạo thành cụm từ trung tâm ngữ, tương đương với cụm danh từ để thay thế', '这本书不是我的。/Zhè běn shū bú shì wǒ de/ Cuốn sách này không phải của tôi. 这块表是你的吗？/Zhè kuài shǒubiǎo shì nǐ de ma/');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', '"一下 /yí xià/', 'Dùng sau động từ, biểu thị một hành động ngắn ngủi.', '我看一下。 /Wǒ kàn yíxià/ Tôi xem một chút. 你休息一下吧。/Nǐ xiūxī yíxià ba/ Bạn nghỉ ngơi một chút đi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Phó từ ngữ khí "真 /zhēn/”', 'Dùng để nhấn mạnh mức độ cao của một tính chất hoặc trạng thái, đồng thời bộc lộ cảm xúc chân thật của người nói.', '你真好！/Nǐ zhēn hǎo/ Bạn thật tốt!/ 你女儿的房间真漂亮！/Nǐ nǚ''ér de fángjiān zhēn piàoliang/ Phòng của con gái bạn thật đẹp!');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Cấu trúc "是...的 /shì... de/', 'Dùng để nhấn mạnh chi tiết (thời gian, địa điểm, cách thức, đối tượng, mục đích...) của một sự việc đã xảy ra trong quá khứ.', '这本书是我买的。/Zhè běn shū shì wǒ mǎi de/ Cuốn sách này là do tôi mua. 手机不是我弄坏的。/Shǒujī bú shì wǒ nòng huài de/ Điện thoại không phải là tôi làm hỏng đâu.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Cấu trúc diễn tả thời gian "......的 时候" /de shí hou/', 'Dùng để chỉ một thời điểm hoặc khoảng thời gian cụ thể khi một sự việc xảy ra.', '睡觉的时候，请保持安静。 /Shuìjiào de shíhou, qǐng bǎochí ānjìng/ Khi ngủ, hãy giữ yên lặng. 你忙的时候，不用回我的消息。 /Nǐ máng de shíhou, búyòng huí wǒ de xiāoxi/ Khi bạn bận, không cần phải trả lời tin nhắn của tôi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Phó từ "就 /jiù/', 'Biểu thị thừa nhận, chấp nhận, đưa ra kết luận hợp logic hoặc giải pháp. Cấu trúc: "就 + động từ/cụm động từ".', '你既然不喜欢这份工作，那就辞职吧。 /Nǐ jìrán bù xǐhuan zhè fèn gōngzuò, nà jiù cízhí ba/ Cậu đã không thích công việc này, vậy thì nghỉ việc đi. 天气这么冷，你穿这么少，就会感冒的。 /Tiānqì zhème lěng, nǐ chuān zhème shǎo, jiù huì gǎnmào de/ Thời tiết lạnh thế, cậu mặc ít vậy, ắt là sẽ bị cảm.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Phó từ ngữ khí " 还" /hái/', 'Cấu trúc "还 + hình dung từ" hoặc "还 + tính từ" thường dùng để diễn tả sự tán thành, chấp nhận được.', '你还知道回来啊？/Nǐ hái zhīdào huílái a/ Còn biết về đấy à? 今天还挺冷的。/Jīntiān hái tǐng lěng de/ Hôm nay còn khá lạnh đấy.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Phó từ chỉ mức độ "有点儿" /yǒu diǎnr/', 'Dùng để diễn tả cảm xúc tiêu cực hay thái độ không hài lòng của người nói.', '今天 天气 有点儿 冷。/Jīntiān tiānqì yǒudiǎnr lěng/ Hôm nay thời tiết hơi lạnh. 我 昨晚 睡 有点儿 晚。/Wǒ zuówǎn shuì yǒudiǎnr wǎn/ Tối qua tôi ngủ hơi muộn.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Đại từ nghi vấn "怎么 /zěnme/”', 'Dùng cấu trúc "怎么 + động từ/tính từ" để hỏi về nguyên nhân của sự việc nào đó và thường diễn tả thái độ ngạc nhiên, kỳ lạ.', '你怎么不高兴？/Nǐ zěnme bù gāoxìng/ Sao bạn không vui? 今天 怎么 这么 热？/Jīntiān zěnme zhème rè/ Sao hôm nay nóng thế?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Sự lặp lại lượng từ', 'Lượng từ (量词) khi được lặp lại sẽ có dạng "AA" hoặc "一AA", biểu thị ý nghĩa "mỗi/từng...", "từng cái một", "rất nhiều", hoặc tạo nhịp điệu, tính hình tượng cho câu văn.', '这些苹果个个都很甜。 /Zhèxiē píngguǒ gègè dōu hěn tián/ Những quả táo này quả nào cũng rất ngọt. 这个商店的衣服件件都很漂亮。 /Zhège shāngdiàn de yīfu jiàn jiàn dōu hěn piàoliang/ Quần áo ở cửa hàng này cái nào cũng rất đẹp.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Cấu trúc "因为..., 所以... /yīnwèi..., suǒyǐ.../', 'Kết nối hai phần câu, trong đó một phân câu biểu thị nguyên nhân, một phân câu biểu thị kết quả.', '因为天气不好，所以我没去商店。 /Yīnwèi tiānqì bù hǎo, suǒyǐ wǒ méi qù shāngdiàn/ Bởi vì thời tiết không tốt, nên tôi không đi cửa hàng. 因为汉字太难了，所以我不喜欢写汉字。 /Yīnwèi Hànyǔ tài nán le, suǒyǐ wǒ bù xǐhuān xiě Hànzì/ Bởi vì chữ Hán khó quá, nên tôi không thích viết chữ Hán.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Phó từ ngữ khí "还 /hái/”', 'Biểu thị hành động hoặc trạng thái vẫn đang tiếp diễn.', '八点了，他还在睡觉。/Bā diǎn le, tā hái zài shuìjiào/ - Tám giờ rồi, anh ấy vẫn còn ngủ. 你怎么还没吃饭？/Nǐ zěnme hái méi chī fàn/ Sao bạn vẫn chưa ăn cơm?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Phó từ chỉ thời gian "就" /jiù/', 'Nhấn mạnh sự việc xảy ra sớm, thuận lợi hoặc đạt được quan điểm của người nói.', '电影 七点开始， 他六点 就 来了。 /Diànyǐng qī diǎn kāishǐ, tā liù diǎn jiù lái le/ Phim 7 giờ bắt đầu, anh ấy 6 giờ đã đến rồi. 我 昨天 就 知道这个消息了。 /Wǒ zuótiān jiù zhīdào zhège xiāoxi le/ Tôi hôm qua đã biết tin này rồi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Giới từ "离" /lí/', 'Giới từ "离" dùng để biểu thị khoảng cách trong không gian hoặc thời gian giữa hai điểm. Nó tương đương với "cách", "xa", "từ... đến..." trong tiếng Việt.', '我家离学校很远 /Wǒ jiā lí xuéxiào hěn yuǎn/ Nhà tôi cách trường rất xa. 学校离机场有20公里。 /Xuéxiào lí jīchǎng yǒu èr shí gōnglǐ/ Trường học cách sân bay 20 km.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Trợ từ ngữ khí " 呢" /ne/', 'Dùng ở cuối câu trần thuật sau động từ/tính từ, biểu thị sự khẳng định, tin tưởng.', '八点上课，时间还早呢。 /Bā diǎn shàngkè, shíjiān hái zǎo ne/ Tám giờ vào lớp, thời gian vẫn còn sớm. 医院离我们 这儿还远呢。 /Yīyuàn lí wǒmen zhèr hái yuǎn ne Bệnh viện cách chỗ chúng ta còn xa đấy.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Câu hỏi có cấu trúc "......, 好吗? /hǎo ma/', 'Thường dùng để hỏi ý kiến, quan điểm của người khác.', '我们一起去吃饭，好吗？ /Wǒmen yìqǐ qù chī fàn, hǎo ma/ Chúng ta cùng đi ăn cơm nhé? 你明天下午给我打电话，好吗？ /Nǐ míngtiān xiàwǔ gěi wǒ dǎ diànhuà, hǎo ma/ Chiều mai bạn gọi điện thoại cho tôi nhé?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Phó từ "再 /zài/', 'Biểu thị một hành động hoặc trạng thái lặp lại hoặc tiếp tục diễn ra.', '你再看看这本书。/Nǐ zài kàn kàn zhè běn shū/ Bạn xem lại cuốn sách này đi. 你明天再给我打电话吧。 /Nǐ míngtiān zài gěi wǒ dǎ diànhuà ba/ Ngày mai bạn gọi điện thoại cho tôi nhé.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Câu kiêm ngữ (兼语)', 'Câu kiêm ngữ do hai cụm động từ tạo thành, trong đó động từ thứ nhất thường là "请 /qǐng/, 让 /ràng/, 叫 /jiào/". Cấu trúc: Chủ ngữ 1 + Động từ 1 + Kiêm ngữ + Động từ 2 + (Tân ngữ)', '我请你吃饭。/Wǒ qǐng nǐ chī fàn/ Tôi mời bạn ăn cơm.老师 让 我 写 汉字。/Lǎoshī ràng wǒ xiě Hànzì/ Giáo viên bảo tôi viết chữ Hán.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Sự lặp lại động từ', 'Dùng để biểu thị thời gian ngắn, số lượng ít, nhẹ nhàng, thử.', '我看看你的新手机。 /Wǒ kànkan nǐ de xīn shǒujī/ Tôi xem thử điện thoại mới của bạn. 让我想想再回答。 /Ràng wǒ xiǎngxiǎng zài huídá/ Để tôi nghĩ một chút rồi trả lời.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Bổ ngữ chỉ kết quả', 'Một số động từ hoặc hình dung từ có thể dùng sau động từ để bổ sung, giải thích kết quả của hành động.', '我看见你的朋友了。/Wǒ kàn jiàn nǐ de péngyǒu le/ Tôi nhìn thấy bạn của bạn rồi. 大卫找到工作了。/Dàwèi zhǎo dào gōngzuò le/ Đại Vệ đã tìm được việc làm rồi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Giới từ "从" /cóng/', '"从" dùng để biểu thị điểm mốc khoảng thời gian, quãng đường, hoặc trình tự.', '商店从上午九点 开到下午六点。 /Shāngdiàn cóng shàngwǔ jiǔ diǎn kāi dào xiàwǔ liù diǎn/ Cửa hàng mở cửa từ 9 giờ sáng đến 6 giờ chiều. 从这儿到地铁站怎么走？ /Cóng zhèr dào dìtiě zhàn zěnme zǒu/ Từ đây đến ga tàu điện đi thế nào?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Cách diễn tả thứ tự "第..." /dì.../', '"第" thường được dùng trước cụm từ chỉ số lượng để nói về thứ tự.', '第一本书 /Dì yī běn shū/ Cuốn sách thứ nhất. 第二次跳舞 /Dì èr cì tiàowǔ/ Lần múa thứ hai.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Câu cầu khiến " 不要...了"; "别... 了"; "不...了"', 'Biểu thị sự ngăn cản, cấm đoán làm việc gì đó.', '不要 玩 手机 了。/Bú yào wán shǒujī le/ Đừng chơi điện thoại nữa. 别睡觉了。/Bié shuìjiào le/ Đừng ngủ nữa.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Giới từ "对" /duì/', '"对" có thể biểu thị mối quan hệ đối đãi giữa người và người, vật và vật, sự vật và sự vật.', '跑步对身体很好。 /Pǎobù duì shēntǐ hěn hǎo/ Chạy bộ rất tốt cho sức khỏe. 看电视 对 学习 汉语 有 帮助。 /Kàn diànshì duì xuéxí Hànyǔ yǒu bāngzhù/ Xem TV có ích cho việc học tiếng Hán.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Cấu trúc có động từ/cụm động từ làm định ngữ', 'Khi động từ hoặc cụm động từ được dùng làm định ngữ, phải thêm "的" vào giữa định ngữ và trung tâm ngữ.', '新买的自行车 /xīn mǎi de zìxíngchē/ Chiếc xe đạp mới mua. 和你一起唱歌的人 /hé nǐ yìqǐ chànggē de rén/ Người hát cùng với bạn.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Câu có từ "比" /bǐ/', 'Dùng "比" biểu thị sự so sánh. Vị ngữ của câu có thể là tính từ.', '哥哥比姐姐高。/Gēge bǐ jiějie gāo/ Anh trai cao hơn chị gái. 今天比昨天热。/Jīntiān bǐ zuótiān rè/ Hôm nay nóng hơn hôm qua.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Câu có từ "比" diễn tả sự khác biệt', 'Dùng số lượng biểu thị sự khác biệt.', '西瓜比苹果贵两块钱。 /Xīguā bǐ píngguǒ guì liǎng kuài qián/ Dưa hấu đắt hơn táo hai tệ. 她比我们老师小两岁。 /Tā bǐ wǒmen lǎoshī xiǎo liǎng suì/ Cô ấy nhỏ hơn giáo viên của chúng tôi hai tuổi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Trợ động từ "可 能" /kěnéng/', 'Biểu thị sự phỏng đoán, có lẽ, có thể. Thường dùng trước động từ hoặc sau chủ ngữ.', '他可能就知道这件事情了。 /Tā kěnéng jiù zhīdào zhè jiàn shìqing le Có lẽ anh ấy biết chuyện này rồi. 你可能不认识他。 /Nǐ kěnéng bù rènshi tā/ Bạn có thể không quen biết anh ấy.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Bổ ngữ chỉ trạng thái (状态补语)', 'Bổ ngữ trạng thái dùng để mô tả kết quả, mức độ hoặc trạng thái của hành động, thường dùng trợ động từ "得" (de).', '他跑得很快。 /Tā pǎo de hěn kuài/ Anh ấy chạy rất nhanh.房间打扫得特别干净。 /Fángjiān dǎsǎo de tèbié gānjìng/ Phòng được dọn đặc biệt sạch sẽ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Câu có từ "比" /bǐ/ với bổ ngữ trạng thái', 'Nếu động từ có bổ ngữ trạng thái, "比" có thể đặt trước động từ hoặc trước bổ ngữ.', '他比我学得好。/Tā bǐ wǒ xué de hǎo/ Anh ấy học tốt hơn tôi. 他比我跑得快得多。 /Tā bǐ wǒ pǎo de kuài de duō/ Anh ấy chạy nhanh hơn tôi nhiều.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Trợ động thái " 着" /zhe/', 'Đặt sau động từ, có thể biểu thị sự duy trì của một trạng thái nào đó.', '门开着。/Mén kāi zhe/ Cửa đang mở. .他们穿着红色的衣服。 /Tāmen chuān zhe hóngsè de yīfu/ Họ đang mặc quần áo màu đỏ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Câu hỏi phản vấn "不是......吗?"', 'Thường dùng để nhắc nhở hoặc biểu thị sự không hiểu, không hài lòng.', '不是今天没有雨吗？ /Bú shì jīntiān méiyǒu yǔ ma/ Không phải hôm nay không có mưa sao? 不是你是北京人吗？ /Bú shì nǐ shì Běijīng rén ma/ Không phải bạn là người Bắc Kinh sao?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Giới từ "往" /wǎng/', '"往" thường dùng để chỉ phương hướng.', '从这儿往前走，就是我们 学校。 /Cóng zhèr wǎng qián zǒu, jiù shì wǒmen xuéxiào/ Từ đây đi về phía trước là trường của chúng tôi. 你看，往左是医院，往右是银行。 /Nǐ kàn, wǎng zuǒ shì yīyuàn, wǎng yòu shì yínháng Bạn xem, rẽ trái là bệnh viện, rẽ phải là ngân hàng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Trợ động thái " 过" /guò/', 'Đặt sau động từ, dùng để biểu thị kinh nghiệm đã trải qua trong quá khứ.', '他们来过我家。 /Tāmen lái guo wǒ jiā/ Họ đã từng đến nhà tôi. 我看过那个电影。/Wǒ kàn guo nàge diànyǐng/ Tôi đã từng xem bộ phim đó.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Cấu trúc "虽然..., 但是..." (suīrán..., dànshì...)', 'Kết nối hai phân câu, cấu thành quan hệ chuyển ngoặt.', '虽然外面很冷，但是房间里很热。 /Suīrán wàimiàn hěn lěng, dànshì fángjiān lǐ hěn rè/ Mặc dù bên ngoài rất lạnh, nhưng trong phòng rất ấm. 虽然汉语很难，但是我很喜欢写汉字。 /Suīrán Hànyǔ hěn nán, dànshì wǒ hěn xǐhuān xiě Hànzì/ Mặc dù tiếng Hán khó, nhưng tôi rất thích viết chữ Hán.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Bổ ngữ chỉ tần suất "次" /cì/', 'Thường đặt sau động từ, dùng để biểu thị số lần động tác xảy ra.', '我们看过三次电影。/Wǒmen kàn guò sān cì diànyǐng/ - Chúng tôi đã xem phim ba lần. 他们坐过飞机一次。/Tāmen zuò guò fēijī yī cì/ Họ đã từng đi máy bay một lần.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Cấu trúc diễn tả trạng thái của hành động "要... 了" /yào... le/', 'Diễn tả một hành động/sự việc sắp diễn ra ngay lập tức, thường trong vài phút, vài giờ, hoặc tương lai rất gần. Cấu trúc: Chủ ngữ + 要 + [Động từ/Cụm động từ] + 了', '火车要来了。 /Huǒchē yào lái le/ Tàu hỏa sắp đến rồi. 新的一年快要到了。 Xīn de yī nián kuàiyào dào le/ Năm mới sắp đến rồi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', 'Cấu trúc "都...了 " /dōu... le/', 'Biểu thị ý nghĩa "đã", thường chứa sự nhấn mạnh hoặc ngữ khí không hài lòng.', '都8点了，快点儿起床吧。 /Dōu bā diǎn le, kuài diǎnr qǐchuáng ba/ Đã 8 giờ rồi, mau dậy đi. 你都十岁了，可以自己洗衣服了。 /Nǐ dōu shí suì le, kěyǐ zìjǐ xǐ yīfu le/ Bạn đã 10 tuổi rồi, có thể tự giặt quần áo rồi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', '1', 'Trợ động từ "要" /yào/ và Cấu trúc "要...了" (sắp/muốn)', '"要" và cấu trúc diễn tả hành động sắp xảy ra ("要...了" hoặc "快要...了") là các cấu trúc cơ bản và quan trọng, xuất hiện trong mọi đề thi để hỏi về dự định hoặc phán đoán thời gian.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', '2', 'Cấu trúc "是...的" /shì... de/(Nhấn mạnh)', 'Cấu trúc dùng để nhấn mạnh chủ thể, thời gian, hoặc cách thức thực hiện hành động được kiểm tra thường xuyên trong các bài tập đối thoại và câu kể, đặc biệt là trong phần Đọc hiểu (Ghép nối).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', '3', 'Bổ ngữ chỉ kết quả', 'Các bổ ngữ chỉ kết quả như "完" /wán/, "见" /jiàn/, "错" /cuò/, "懂" /dǒng/, "到" /dào/ xuất hiện rộng rãi để kiểm tra việc hoàn thành hay kết quả của hành động, đặc biệt trong phần đọc hiểu và hội thoại.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', '4', 'Giới từ "离" /lí/ (Chỉ khoảng cách)', '"离" là giới từ cốt lõi ở HSK 2, dùng để diễn tả khoảng cách địa lý hoặc thời gian. Nó luôn được kiểm tra trong các bài về địa điểm (sân bay, trường học, nhà ga).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', '5', 'Cấu trúc so sánh "比" /bǐ/ Câu so sánh sự khác biệt', 'Câu chữ "比" là cấu trúc so sánh cơ bản nhất, dùng để diễn tả sự hơn kém giữa hai đối tượng. Cấu trúc này liên tục xuất hiện, đôi khi kèm theo số lượng để diễn tả sự khác biệt.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', '6', 'Phó từ "再" /zài/ Lặp lại/Tiếp tục', '"再" biểu thị hành động lặp lại hoặc tiếp diễn, là một phó từ quan trọng trong các đoạn hội thoại về kế hoạch hoặc thay đổi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', '7', 'Bổ ngữ chỉ trạng thái "得" /de/', 'Bổ ngữ trạng thái "得" được sử dụng để mô tả hoặc đánh giá mức độ, kết quả của hành động.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 2', '8', 'Đại từ nghi vấn "怎么" /zěnme/ (Hỏi nguyên nhân)', '"怎么" dùng để hỏi nguyên nhân hoặc cách thức, thường mang ngữ khí ngạc nhiên, đây là từ khóa quan trọng trong các câu hỏi lắng nghe về lý do hoặc cách làm việc gì đó.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Kết quả ngữ "好" /hǎo/', 'Đặt sau động từ, biểu thị hành động đã được hoàn thành và đạt được kết quả thỏa đáng .', '我吃好了。/Wǒ chī hǎo le/ -> Tôi đã ăn ăn no rồi 你准备好了吗？/Nǐ zhǔnbèi hǎo le ma/ -> Bạn chuẩn bị xong chưa?)');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc phủ định tuyệt đối (一...也/都 + 不/ 没)', 'Dùng để diễn tả sự phủ định hoàn toàn. Khi vị ngữ là tính từ, thường dùng "一 点儿也/都 + 不 + tính từ".', '我一点儿东西也不想吃。 /Wǒ yìdiǎnr dōngxi yě bù xiǎng chī/ -> Một chút đồ ăn tôi cũng không muốn ăn.) 他一点儿也不累。 /Tā yìdiǎnr yě bù lèi/ Anh ấy một chút cũng không mệt.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Liên từ "那" /nà/', 'Đặt ở đầu câu, dùng để chỉ kết quả hay nhận xét dựa vào nội dung đã được đề cập trước đó.', '1.A: 我不想去看电影。/Wǒ bù xiǎng qù kàn diànyǐng/ Tôi không muốn đi xem phim. B: 那我也不去了。/Nà wǒ yě bù qù le/ Thế thì tôi cũng không đi nữa. 2. A: 我早复习好了。/Wǒ zǎo fùxí hǎo le/ Tôi đã ôn tập xong sớm rồi. B: 那也不能一直玩儿啊。/Nà yě bù néng yìzhí wánr a/ Thế thì cũng không thể cứ chơi mãi được.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Bổ ngữ chỉ phương hướng đơn giản', 'Đặt sau động từ, biểu thị phương hướng của hành động. Thường dùng với các động từ có cùng phương hướng như 上, 下, 进, 出, 回, 过, 起.', '我们在楼上等你呢，你上来吧。 /Wǒmen zài lóu shàng děng nǐ ne, nǐ shàng lái ba/ -> Chúng tôi ở trên lầu đợi bạn đấy, bạn lên đây đi. 你把这张椅子搬过去吧。 /Nǐ bǎ zhè zhāng yǐzi bān guòqù ba/ -> Bạn chuyển cái ghế này qua đó đi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Hai động từ/hành động liên tiếp (Động tác liền kề)', 'Cấu trúc "Động từ 1 + 了 + 就 + Động từ 2" dùng để diễn tả hai hành động xảy ra liên tiếp, hành động thứ hai nối tiếp ngay sau hành động thứ nhất.', '我下了课就吃饭。 /Wǒ xià le kè jiù chī fàn/ -> Tôi tan học là ăn cơm ngay. 妈妈起了就做早饭。 /Māma qǐ le jiù zuò zǎofàn/ -> Mẹ thức dậy là làm bữa sáng ngay.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Phản vấn: Câu hỏi có cấu trúc " 能......吗"', 'Dùng để biểu thị sự phản đối. Nếu giữa "能......吗" là hình thức khẳng định biểu đạt ý phủ định.', '你不做作业，也不练习，能学好吗？ /Nǐ bù zuò zuòyè, yě bù liànxí, néng xué hǎo ma/ -> Bạn không làm bài tập, cũng không luyện tập, làm sao mà học tốt được 你每天晚上吃了饭就睡觉，也不出去走走，能不 胖吗？ /Nǐ měitiān wǎnshàng chī le fàn jiù shuìjiào, yě bù chūqù zǒuzou, néng bù pàng ma/ -> Bạn mỗi tối ăn cơm xong là đi ngủ, cũng không ra ngoài đi dạo, làm sao mà không béo được?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', '"还是" /háishì/ và "或者" /huòzhě/', 'Cả hai đều biểu thị sự lựa chọn. "还是" dùng trong câu hỏi nghi vấn, "或者" dùng trong câu trần thuật.', '还是: 你喜欢喝咖啡还是喝茶？/Nǐ xǐhuan hē kāfēi háishì hē chá/ Bạn thích uống cà phê hay trà? 或者: 明天是晴天或者阴天都可以。/Míngtiān shì qíngtiān huòzhě yīntiān dōu kěyǐ/ Ngày mai trời nắng hoặc trời râm đều được.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc diễn tả sự tồn tại', 'Dùng để biểu thị vị trí tồn tại của sự vật. Cấu trúc cơ bản là "Từ/cụm từ chỉ vị trí + Động từ + 着 + Cụm danh từ".', '桌子上放着一杯咖啡。/Zhuōzi shàng fàng zhe yī bēi kāfēi/ Trên bàn đặt một tách cà phê/ 冰箱里放着很多水果。/Bīngxiāng lǐ fàng zhe hěn duō shuǐguǒ/ Trong tủ lạnh để rất nhiều hoa quả.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Trợ động từ "会" /huì/', 'Dùng trong câu biểu thị khả năng. Thường dùng để diễn tả những sự việc chưa xảy ra.', '你穿得那么少，会感冒的。/Nǐ chuān de nàme shǎo, huì gǎnmào de/ Bạn mặc ít đồ như vậy, sẽ bị cảm lạnh đấy. 喝杯热茶会很舒服。/Hē bēi rè chá huì hěn shūfu/ Uống một tách trà nóng sẽ rất dễ chịu.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc "又... 又..." /yòu... yòu.../', 'Cấu trúc "又 + tính từ 1 + 又 + tính từ 2" dùng để đề cập đến hai đặc điểm cùng tồn tại ở một người hay sự vật.', '这个西瓜又大又甜。/Zhège xīguā yòu dà yòu tián/ Quả dưa hấu này vừa to vừa ngọt. 她工作又认真又热情。/Tā gōngzuò yòu rènzhēn yòu rèqíng/ Cô ấy làm việc vừa nghiêm túc vừa nhiệt tình.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Động tác kèm trạng thái', 'Cấu trúc "Động từ 1 + 着 + (trạng thái), Động từ 2 + (tân ngữ 2)" biểu thị hai hành động xảy ra đồng thời, diễn tả trạng thái hoặc cách thức tiến hành hành động thứ hai.', '小丽站着跟同事聊天儿。/Xiǎo Lì zhàn zhe gēn tóngshì liáotiānr/ Tiểu Lệ đứng trò chuyện với đồng nghiệp. 她总是笑着跟客人说话。/Tā zǒng shì xiào zhe gēn kèrén shuōhuà/ Cô ấy luôn cười nói chuyện với khách hàng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Trợ từ chỉ sự thay đổi "了" /le/', 'Biểu thị tình huống đã thay đổi, hoặc xuất hiện tình huống mới.', '我以前有钱，现在没钱了。/Wǒ yǐqián yǒu qián, xiànzài méi qián le/ Trước đây tôi có tiền, giờ không có tiền nữa. 这条裙子是去年的，今年就不能穿了。 /Zhè tiáo qúnzi shì qùnián de, jīnnián jiù bùnéng chuān le/ Chiếc váy này là của năm ngoái, năm nay không mặc được nữa rồi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc "越来越 + tính từ/động từ trạng thái"', 'Biểu thị sự thay đổi theo thời gian, hoặc sự thay đổi mức độ. Không dùng phó từ chỉ mức độ 更.', '这个问题越来越复杂。/Zhège wèntí yuè lái yuè fùzá/ Vấn đề này càng lúc càng phức tạp. 他的汉语说得越来越流利。/Tā de Hànyǔ shuō de yuè lái yuè liúlì/ Tiếng Trung của anh ấy nói ngày một lưu loát.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Bổ ngữ chỉ khả năng', 'Dùng để diễn tả khả năng có thể thực hiện được một kết quả nào đó. Công Thức Cơ Bản: Khẳng định: Động từ + 得 + Bổ ngữ (kết quả/phương hướng) Phủ định: Động từ + 不 + Bổ ngữ (kết quả/phương hướng) Dạng câu hỏi chính phản: Động từ + 得 + Bổ ngữ + Động từ + 不 + Bổ ngữ？', 'Phủ định: 这个汉字太难，我写不对。 /Zhège Hànzì tài nán, wǒ xiě bù duì/ Chữ Hán này khó quá, tôi viết không đúng. Khẳng định: 你说慢一点儿，我听得懂 /Nǐ shuō màn yīdiǎnr, wǒ tīng de dǒng/ Bạn nói chậm một chút, tôi có thể nghe hiểu. Câu hỏi: 这么多作业，你今天做得完做不完？ /Zhème duō zuòyè, nǐ jīntiān zuò de wán zuò bù wán/ Nhiều bài tập thế này, hôm nay bạn làm xong được không?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Đại từ nghi vấn dùng để hỏi vị trí "哪" /nǎ/', '"哪" (thường dùng cùng với "儿" trong khẩu ngữ thành "哪儿") là đại từ nghi vấn dùng để hỏi về địa điểm, nơi chốn. Nó có nghĩa là "đâu, nơi nào".', '卫生间在哪儿？/Wèishēngjiān zài nǎr/ Nhà vệ sinh ở đâu? 你去哪儿？/Nǐ qù nǎr/ Bạn đi đâu?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Phân biệt "刚" /gāng/ và "刚才" /gāngcái/', '"刚才" là danh từ chỉ thời gian, chỉ hành động xảy ra trong thời gian ngắn. "刚" là phó từ, biểu thị hành động xảy ra cách thời điểm nói không lâu, thời gian ngắn hơn.', '刚才: 刚才我喝了一杯咖啡。 /Gāngcái wǒ hē le yī bēi kāfēi/ Lúc nãy tôi đã uống một tách cà phê. 刚: 我刚喝完一杯咖啡。/Wǒ gāng hē wán yī bēi kāfēi/ Tôi vừa mới uống xong một tách cà phê.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cách diễn tả khoảng thời gian', 'Dùng cấu trúc "Chủ ngữ + động từ + 了 + khoảng thời gian + tân ngữ + 了" diễn tả hành động đang tiếp diễn.', '我学习了两年汉语了。/Wǒ xuéxí le liǎng nián Hànyǔ le/ Tôi đã học tiếng Hán được hai năm rồi. 我们在这儿坐了半个小时了。/Wǒmen zài zhèr zuò le bàn gè xiǎoshí le/ Chúng tôi đã ngồi ở đây được nửa tiếng rồi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc "对...... 感兴趣" và " 对......有兴趣"', 'Dùng để diễn tả sự hứng thú đối với điều gì đó.', '他们对电影不感兴趣。/Tāmen duì diànyǐng bù gǎn xìngqù/ Họ không hứng thú với phim ảnh. 同学们对打篮球很感兴趣。/Tóngxuémen duì dǎ lánqiú hěn gǎn xìngqù/ Các bạn học rất hứng thú với bóng rổ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Dùng "刻", "半", "差" diễn tả thời gian', 'Dùng để biểu thị thời gian. "刻" /kè/: Mười lăm phút "半" /bàn/: "Rưỡi" hoặc "ba mươi phút "差" /chà/: Thiếu, kém, chưa tới.', '三点一刻 /Sān diǎn yí kè /Ba giờ mười lăm 差五分八点 /Chà wǔ fēn bā diǎn /Kém năm phút tám giờ. (Tức là 7:55) 六点半 /Liù diǎn bàn/ Sáu giờ rưỡi / Sáu giờ ba mươi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', '"又" /yòu/ và "再 " /zài/', '"又" biểu thị hành động hoặc tình huống lặp lại đã xảy ra. "再" biểu thị hành động hoặc tình huống lặp lại chưa xảy ra.', '又: 你上午已经喝了一杯咖啡，下午怎么又喝了 一杯？/Nǐ shàngwǔ yǐjīng hē le yī bēi kāfēi, xiàwǔ zěnme yòu hē le yī bēi/ Buổi sáng bạn đã uống một ly cà phê rồi, buổi chiều sao lại uống thêm một ly nữa? 再: 你只吃了一点儿饭，再吃一点儿吧。/Nǐ zhǐ chī le yīdiǎn fàn, zài chī yīdiǎn ba/ Bạn chỉ ăn một chút cơm, ăn thêm chút nữa đi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Đại từ nghi vấn dùng linh hoạt', 'Dùng hai đại từ nghi vấn giống nhau, biểu thị sự tương đồng về đối tượng, hành động hoặc phương thức.', '什么东西便宜我就买什么。/Shénme dōngxi piányi wǒ jiù mǎi shénme/ Cái gì rẻ thì tôi mua cái đó. 你坐哪儿我就坐哪儿。/Nǐ zuò nǎr wǒ jiù zuò nǎr/ Bạn ngồi đâu thì tôi ngồi đó.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc "越A越 B" /yuè A yuè B/', 'Biểu thị sự thay đổi đi kèm với sự thay đổi của A (càng... càng).', '雨越下越大了。/Yǔ yuè xià yuè dà le/ Mưa càng lúc càng to. 你说的中文越说越好了。/Nǐ shuō de Zhōngwén yuè shuō yuè hǎo le/ Tiếng Trung của bạn càng nói càng hay.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc so sánh 1: "A 跟 B 一样 + (tính từ)"', 'Dùng để so sánh A và B, kết quả tương đồng. Phủ định thì thêm "不" trước "一 样".', '这本书跟那本书一样。/Zhè běn shū gēn nà běn shū yīyàng/ Quyển sách này giống quyển sách kia. 她的汉语说得跟中国人一样好。 /Tā de Hànyǔ shuō de gēn Zhōngguó rén yīyàng hǎo/ Tiếng Hán của cô ấy nói hay như người Trung Quốc.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc so sánh 2: "A 比 B + tính từ + bổ sung mức độ"', 'Dùng để so sánh sự khác biệt về mức độ (như 一点儿/一些/得多/多了).', '大山比大卫高一点儿。 /Dàshān bǐ Dàwèi gāo yīdiǎn/ Đại Sơn cao hơn Đại Vệ một chút 数学比历史难多了。 /Shùxué bǐ lìshǐ nán duō le/ Môn Toán khó hơn môn Lịch sử nhiều.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cách diễn tả số ước lượng (1)', 'Dùng hai số đếm liên tiếp (như 二三, 三 四) để diễn tả số lượng ước chừng.', '你每天都喝三四杯咖啡了，别再喝了。/Nǐ měitiān dōu hē sān sì bēi kāfēi le, bié zài hē le/ Ngày nào bạn cũng uống ba bốn ly cà phê rồi, đừng uống nữa. 我们已经学了两三个小时。/Wǒmen yǐjīng xué le liǎng sān gè xiǎoshí/ Chúng tôi đã học được khoảng hai ba tiếng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc với "把" (1)', 'Dùng để chỉ hành động được thực hiện, có tác động đến đối tượng B và làm cho đối tượng thay đổi hoặc hoàn thành một việc gì đó.', '请同学们把书拿出来。/Qǐng tóngxuémen bǎ shū ná chūlái/ Mời các bạn học sinh lấy sách ra. 你把灯关了吧。/Nǐ bǎ dēng guān le ba/ Bạn tắt đèn đi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cách diễn tả số ước lượng (2)', 'Dùng "左右" /zuǒyòu/ sau số để diễn tả số ước lượng (khoảng).', '周末我一般十点左右起床。 /Zhōumò wǒ yībān shí diǎn zuǒyòu qǐchuáng/ Cuối tuần tôi thường dậy vào khoảng mười giờ. 我们公司有五百人左右。/Wǒmen gōngsī yǒu wǔbǎi rén zuǒyòu/ Công ty chúng tôi có khoảng năm trăm người.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Phân biệt "才" /cái/ và "就" /jiù/', '"就" biểu thị hành động xảy ra sớm, nhanh, thuận lợi. "才" biểu thị hành động xảy ra muộn, chậm, không thuận lợi.', '(就): 我早上五点就起床了。/Wǒ zǎoshang wǔ diǎn jiù qǐchuáng le/ Tôi sáng năm giờ đã dậy rồi. (才): 八点上课，他九点才起来。/Bā diǎn shàngkè, tā jiǔ diǎn cái qǐlái/ Tám giờ vào học, anh ấy chín giờ mới dậy.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc với "把" (2)', 'Diễn tả một hành động làm cho vị trí của đối tượng B bị thay đổi (A把B + Động từ + 在/到/给/...).', '我把照片放在你包里了。/Wǒ bǎ zhàopiàn fàng zài nǐ bāo li le/ Tôi đã đặt ảnh vào trong túi của bạn rồi. 你帮我把这本书带给小丽。/Nǐ bāng wǒ bǎ zhè běn shū dài gěi Xiǎo Lì/ Bạn giúp tôi mang quyển sách này cho Tiểu Lệ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Bổ ngữ chỉ phương hướng kép', 'Bổ ngữ chỉ phương hướng kép là sự kết hợp giữa một động từ chỉ phương hướng đơn giản thứ nhất (上, 下, 进, 出, 回, 过, 起) và một động từ chỉ phương hướng đơn giản thứ hai (来, 去).', '老师拿出了一本书来。/Lǎoshī ná chū le yī běn shū lái./ Thầy giáo lấy ra một quyển sách. 小狗从房间跑出来了。/Xiǎo gǒu cóng fángjiān pǎo chūlái le/ Chú chó nhỏ chạy ra khỏi phòng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc "一 边......一边......"', 'Dùng để diễn tả hai hành động diễn ra đồng thời.', '妈妈一边唱歌一边做饭。/Māmā yībiān chànggē yībiān zuòfàn/ Mẹ vừa hát vừa nấu cơm. 我丈夫喜欢一边吃早饭一边看报纸。 /Wǒ zhàngfu xǐhuan yībiān chī zǎofàn yībiān kàn bàozhǐ/ Chồng tôi thích vừa ăn sáng vừa đọc báo.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc với "把" (3)', 'Hành động làm cho đối tượng B đạt được kết quả nào đó hoặc thay đổi vị trí (A把B + Động từ + Bổ ngữ kết quả/phương hướng).', '我把衣服洗干净了。/Wǒ bǎ yīfu xǐ gānjìng le/ Tôi giặt quần áo sạch sẽ rồi. 你把水果拿过来。 /Nǐ bǎ shuǐguǒ ná guòlái/ Bạn mang hoa quả lại đây.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc "先......, 再......, 然后......"', 'Biểu thị trình tự của các hành động.', '我先洗完澡，然后再给你回电话。/Wǒ xiān xǐ wán zǎo, ránhòu zài gěi nǐ huí diànhuà/ Tôi đi tắm xong trước, sau đó gọi lại cho bạn. 你先把饭菜做好，然后再把一块新鲜的水果放进 去。/Nǐ xiān bǎ fàncài zuò hǎo, ránhòu zài bǎ yī kuài xīnxiān de shuǐguǒ fàng jìnqù/ Bạn làm xong cơm trước, sau đó đặt thêm một miếng hoa quả tươi vào.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc "除 了......以外, 都/还/ 也......"', 'Trừ một phần ra, những phần khác đều tương đồng (都) hoặc bổ sung thêm (还/ 也).', '都: 除了你以外，大家都听懂了。/Chúle nǐ yǐwài, dàjiā dōu tīng dǒng le/ Trừ bạn ra, mọi người đều đã hiểu. 还: 除了唱歌以外，他还喜欢跳舞。/Chúle chànggē yǐwài, tā hái xǐhuan tiàowǔ/ Ngoài ca hát ra, anh ấy còn thích khiêu vũ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Đại từ nghi vấn dùng linh hoạt (2)', 'Dùng "什么" thay thế cho người/sự vật không xác định, biểu đạt ý nhún nhường, lịch sự.', '这个饭馆没有什么特别好吃的菜。/Zhège fànguǎn méiyǒu shénme tèbié hǎo chī de cài/ Quán ăn này không có món nào đặc biệt ngon cả. 你写得很好，没什么问题。/Nǐ xiě de hěn hǎo, méi shénme wèntí/ Bạn viết rất tốt, không có vấn đề gì.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cách biểu đạt mức độ: "极了" /jí le/', '极了" là một từ bổ nghĩa mức độ, đặt sau tính từ hoặc động từ chỉ trạng thái tâm lý, dùng để nhấn mạnh mức độ rất cao.', '我的小狗可爱极了。/Wǒ de xiǎo gǒu kě''ài jíle/ Chú chó nhỏ của tôi đáng yêu vô cùng. 他满意极了。 /Tā mǎnyì jíle/ Anh ấy cực kỳ hài lòng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc điều kiện: "如果......(的 话), (chủ ngữ) 就......"', '"如果" là giả thiết, "就" là kết quả sẽ xảy ra trong điều kiện đó.', '如果你太累了，就休息一会儿。/Rúguǒ nǐ tài lèi le, jiù xiūxí yīhuìr/ Nếu bạn quá mệt rồi, thì nghỉ ngơi một lát đi. 如果你喜欢，我就给你买。/Rúguǒ nǐ xǐhuan, wǒ jiù gěi nǐ mǎi/ Nếu bạn thích, tôi sẽ mua cho bạn.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Bổ ngữ trạng thái phức hợp', 'Dùng "得" /de/ nối động từ/tính từ với cụm bổ ngữ trạng thái, miêu tả trạng thái/mức độ.', '孩子们玩儿得不想回家。 /Háizimen wánr de bù xiǎng huí jiā/ Các con chơi đến mức không muốn về nhà. 他们忙得没有时间跟别人见面。/Tāmen máng de méiyǒu shíjiān gēn biérén jiànmiàn/ Họ bận đến mức không có thời gian gặp ai.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Điệp âm tính từ đơn âm tiết (Hình thức "AA 的")', 'Dùng để miêu tả đặc điểm của người hoặc sự vật.', '你送的红红的花，我很喜欢。/Nǐ sòng de hónghóng de huā, wǒ hěn xǐhuan/ Bó hoa đỏ tươi bạn tặng, tôi rất thích. 你女儿长得白白的，胖胖的，真可爱。/Nǐ nǚ''ér zhǎng de báibái de, pàngpàng de, zhēn kě''ài/ Con gái bạn trắng trẻo, mũm mĩm, thật đáng yêu');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Điệp âm động từ hai âm tiết (Hình thức "ABAB")', 'Biểu đạt hành động xảy ra trong thời gian ngắn, hoặc mang ý thử.', '他是新的，有时间你帮助帮助他吧。/Tā shì xīn de, yǒu shíjiān nǐ bāngzhù bāngzhù tā ba/ Anh ấy là người mới, có thời gian bạn giúp đỡ anh ấy một chút đi. 我真应该多锻炼锻炼了。/Wǒ zhēn yīnggāi duō duànliàn duànliàn le/ Tôi thật sự nên tập thể dục nhiều hơn một chút.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Đại từ nghi vấn dùng linh hoạt (3)', 'Thay thế cho một phạm vi rộng, biểu thị mọi đối tượng đều có tình huống tương đồng.', '谁都喜欢小丽。/Shéi dōu xǐhuan Xiǎo Lì.) - Ai cũng thích Tiểu Lệ. 我们怎么去公园都可以。/Wǒmen zěnme qù gōngyuán dōu kěyǐ/ Chúng ta đi công viên bằng cách nào cũng được.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc điều kiện: "只要......, 就......"', '"只要" là điều kiện cần. "就" là kết quả sẽ xảy ra trong điều kiện đó.', '只要我有时间，就一定跟你去旅游。/Zhǐyào wǒ yǒu shíjiān, jiù yīdìng gēn nǐ qù lǚyóu/ Chỉ cần tôi có thời gian, nhất định sẽ đi du lịch với bạn. 只要你给我钱，我就能照顾好它。/Zhǐyào nǐ gěi wǒ qián, wǒ jiù néng zhàogù hǎo tā/ Chỉ cần bạn đưa tiền cho tôi, tôi sẽ chăm sóc nó tốt.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Giới từ "关于" /guānyú/', 'Giới thiệu đối tượng mà người nói muốn đề cập.', '我最近看了一些关于中国文化的电影。/Wǒ zuìjìn kàn le yīxiē guānyú Zhōngguó wénhuà de diànyǐng/ Gần đây tôi xem một vài bộ phim về văn hóa Trung Quốc. 关于这个工作，还有什么问题吗？/Guānyú zhège gōngzuò, hái yǒu shénme wèntí ma/ Về công việc này, còn có vấn đề gì không?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Mở rộng ý nghĩa của bổ ngữ chỉ phương hướng', '"出来" có thể biểu thị từ không có gì đến có gì, phát sinh sự vật, sự việc mới, hoặc sự phân biệt, nhận ra. "起来" biểu thị sự bắt đầu (hành động/trạng thái), hoặc hồi tưởng/nhớ lại.', '(出来): 照片我选了几张洗出来了。/Zhàopiàn wǒ xuǎn le jǐ zhāng xǐ chūlái le/ Ảnh tôi chọn đã rửa ra mấy tấm rồi. (起来): 你能想起来那是什么时候的事吗？/Nǐ néng xiǎng qǐlái nà shì shénme shíhòu de shì ma/ Bạn có thể nhớ lại chuyện đó là lúc nào không?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Dùng "使" /shǐ/, " 叫" /jiào/, "让" /ràng/', 'Đều dùng để biểu thị ý khiến/mệnh lệnh. "使" (văn viết), "叫/让" (khẩu ngữ).', '(使): 读书使我快乐。/Dúshū shǐ wǒ kuàilè/ Đọc sách khiến tôi vui vẻ. (让): 考试让我很紧张。/Kǎoshì ràng wǒ hěn jǐnzhāng/ Kỳ thi khiến tôi rất hồi hộp.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Câu bị động với " 被" /bèi/', 'Dùng để diễn tả ý bị động. Chủ ngữ là đối tượng chịu tác động.', '我的自行车被偷了。/Wǒ de zìxíngchē bèi tōu le/ Xe đạp của tôi bị trộm rồi. 我被朋友影响了。/Wǒ bèi péngyou yǐngxiǎng le/ Tôi bị bạn bè ảnh hưởng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc "只......, 才......"', '"只" là điều kiện. "才" là kết quả xuất hiện trong điều kiện này.', '只有写完作业，才能看电视。/Zhǐyǒu xiě wán zuòyè, cái néng kàn diànshì/ Chỉ khi làm xong bài tập, mới có thể xem TV. 看起来只有爱，才能让人有变化。/Kàn qǐlái zhǐyǒu ài, cái néng ràng rén yǒu biànhuà/ Có vẻ chỉ có tình yêu, mới có thể khiến người ta thay đổi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Thời - trạng thái hành động', '– Trợ từ 了 (hoàn thành & thay đổi) – Cấu trúc 在……呢 – Cấu trúc 正在……', 'HSK 3 kiểm tra khả năng phân biệt hành động đang diễn ra – đã hoàn thành - sự thay đổi trạng thái, đặc biệt trong phần Nghe và Đọc hiểu.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Trình tự & logic hành động', '– 先……再……然后…… – ……了就……', 'Các cấu trúc này giúp đánh giá khả năng tổ chức trình tự sự việc, thường xuất hiện trong câu dài và hội thoại tình huống.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Động từ năng nguyện (mở rộng)', '– 会 (khả năng/dự đoán) – 能 (điều kiện cho phép) – 应该 (khuyên nhủ, nghĩa vụ)', 'Đề thi HSK 3 chú trọng khả năng diễn đạt ý định, phán đoán và lời khuyên, phản ánh mức độ giao tiếp thực tế cao hơn HSK 1-2.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc so sánh', '– A 跟 B 一样 + tính từ – A 比 B + tính từ (+ 一点儿 /多了)', 'So sánh là dạng ngữ pháp xuất hiện rất thường xuyên trong phần Đọc hiểu và Hoàn thành câu.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Diễn tả mức độ và xu hướng', '– 越来越 + tính từ/động từ – 又……又…… – 极了', 'Giúp người học thể hiện mức độ, sự thay đổi và cảm xúc, là tiêu chí quan trọng của HSK 3.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Bổ ngữ', '– Bổ ngữ kết quả (好、完、对、错…) – Bổ ngữ khả năng (得 / 不)', 'HSK 3 bắt đầu kiểm tra sâu khả năng kết hợp động từ + bổ ngữ, nền tảng cho HSK 4 trở lên.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Cấu trúc với “把” (cơ bản)', '– 把 + tân ngữ + động từ + kết quả/phương hướng', 'Cấu trúc “把” xuất hiện ở mức nhập môn trong HSK 3, thường dùng để kiểm tra nhận diện cấu trúc câu.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Câu điều kiện', '– 如果……就…… – 只要……就……', 'Thường xuất hiện trong phần Đọc hiểu, đánh giá khả năng hiểu mối quan hệ điều kiện – kết quả.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Đại từ nghi vấn dùng linh hoạt', '– 什么 / 哪儿 / 怎么 + 都 / 就', 'HSK 3 yêu cầu người học hiểu đại từ nghi vấn không chỉ dùng để hỏi, mà còn để biểu đạt ý khái quát.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 3', 'Diễn tả thời gian và số lượng ước lượng', '– ……了 + khoảng thời gian + 了 – 左右 / 二三 / 三四', 'Đề thi thường lồng vào bối cảnh sinh hoạt thực tế như học tập, làm việc, sinh hoạt hằng ngày.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '不仅…而且/还 … /bùjǐn… érqiě/hái…/', 'Liên từ, liên kết hai vế câu có mối quan hệ tăng tiến, biểu thị "không những... mà còn...".', '不仅是足球踢得好，而且他也非常热情. /Bùjǐn shì zúqiú tī de hǎo, érqiě tā yě fēicháng rèqíng/ Không chỉ đá bóng giỏi, mà anh ấy còn rất nhiệt tình.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '从来 /cónglái/', 'Phó từ, biểu thị từ trước đến nay đều là như vậy, thường dùng trong câu phủ định.', '我从来 没去过日本。 /Wǒ cónglái méi qù guo Rìběn/ Tôi chưa từng đi Nhật Bản bao giờ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '刚/刚才 /gāng/gāngcái/', 'Phó từ 刚 chỉ hành động xảy ra cách đây không lâu; 刚才 là danh từ chỉ thời gian ngắn trong quá khứ, có thể đứng trước chủ ngữ hoặc sau chủ ngữ và trước động từ,.', '刚才: 我刚才去洗手间了，你给我打电话了 /Wǒ gāngcái qù xǐshǒujiān le, nǐ gěi wǒ dǎ diànhuà le/ Tôi vừa mới đi vệ sinh, bạn đã gọi điện cho tôi sao 刚: 他刚来一会儿. /Tā gāng lái yīhuìr/ Anh ấy vừa mới đến một lát.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '即使…也… /jíshǐ… yě…/', 'Liên từ, biểu thị một sự giả định hoặc tình huống đã xảy ra (dù cho, cho dù), kết quả vẫn không thay đổi.', '即使明天下雨，我们也要去爬山。 /Jíshǐ míngtiān xià yǔ, wǒmen yě yào qù páshān/ Cho dù ngày mai trời mưa, chúng tôi vẫn sẽ đi leo núi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '(在)…上 /zài)… shàng/', 'Danh từ chỉ phương vị, dùng sau danh từ, biểu thị trên bề mặt vật thể hoặc chỉ phạm vi nào đó.', '今天的工作上有很多问题. /Jīntiān de gōngzuò shàng yǒu hěnduō wèntí/ Hôm nay có nhiều vấn đề về công việc.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '正好 /zhènghǎo/', 'Hình dung từ (biểu thị vừa vặn, vừa khéo) Phó từ (biểu thị sự việc xảy ra đúng lúc, đúng thời điểm).', '我妹妹出生那天，正好下雪，所以爸妈叫她“小雪”. /Wǒ mèimei chūshēng nà tiān, zhènghǎo xià xuě, suǒyǐ bà mā jiào tā "Xiǎoxuě"/ Em gái tôi sinh ra ngày hôm đó, vừa đúng lúc tuyết rơi, nên bố mẹ đặt tên nó là "Tiểu Tuyết". 我的冰箱太旧了，正好商场在打折，我们便买一台吧. /Wǒ de bīngxiāng tài jiù le, zhènghǎo shāngchǎng zài dǎzhé, wǒmen biàn mǎi yī tái ba/ Tủ lạnh nhà tôi cũ quá rồi, vừa hay trung tâm thương mại đang giảm giá, chúng ta mua một cái đi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '差不多/几乎 /chàbùduō/jīhū/', 'Phó từ/Hình dung từ: biểu thị, mức độ không khác biệt nhiều gần như, xấp xỉ', '他俩差不多高./Tā liǎng chàbùduō gāo/ Hai người họ gần như cao bằng nhau.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '尽管 /jǐnguǎn/', 'Liên từ, biểu thị dù cho, mặc dù (sự việc đã xảy ra, nhưng kết quả/tình huống vế sau lại bất ngờ hoặc chuyển ý).', '尽管这是一场误会，他仍然不开心 /Jǐnguǎn zhè shì yī chǎng wùhuì, tā réngráng bù kāixīn/ Mặc dù đây là một sự hiểu lầm, anh ấy vẫn không vui.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '却 /què/', 'Phó từ, dùng sau chủ ngữ hoặc trước động từ, biểu thị chuyển ý (nhưng mà, trái lại), ngữ khí nhẹ nhàng hơn "但是 ",.', '很多人虽然住在一个楼里，但却从来没说过话 / Hěn duō rén suīrán zhù zài yī gè lóu lǐ, dàn què cónglái méi shuō guò huà/ Rất nhiều người dù sống cùng một tòa nhà, nhưng lại chưa từng nói chuyện với nhau.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '而 /ér/', 'Liên từ, dùng để nối hai vế câu, biểu thị tăng tiến hoặc chuyển ý/tương phản,.', '即使没有人支持我，我也会继续做下去。 /Jíshǐ méiyǒu rén zhīchí wǒ, wǒ yě huì jìxù zuò xiàqù/ Ngay cả khi không có ai ủng hộ tôi, tôi cũng sẽ tiếp tục làm.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '挺…的 /tǐng… de/', 'Dùng để biểu thị mức độ khá / tương đối /rất, mang sắc thái nhẹ nhàng, tự nhiên trong giao tiếp. Thường dùng trong cấu trúc “挺 + tính từ + 的” để nhận xét hoặc đánh giá một sự việc, người hay trạng thái.', '昨天晚上去的那家饭馆味道挺好的 /Zuótiān wǎnshàng qù de nà jiā fànguǎn wèidào tǐng hǎo de/ Quán ăn tối qua tôi đến khá ngon.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '本来 /běnlái/', 'Phó từ dùng để nói về trạng thái, sự việc ban đầu hoặc theo lẽ thường, trước khi có sự thay đổi xảy ra.', '这件事情本来应该听他的 / Zhè jiàn shìqing běnlái yīnggāi tīng tā de/ Việc này vốn dĩ nên nghe lời anh ấy.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '另外 /lìngwài/', 'Đại từ (chỉ người/vật ngoài phạm vi đã đề cập) Phó từ (chỉ ngoài phạm vi đã đề cập) Liên từ (ngoài ra).', '这本书不好看，我们看另外的吧。/Zhè běn shū bù hǎokàn, wǒmen kàn lìngwài de ba/ Cuốn sách này không hay, chúng ta xem cuốn khác đi. 工资之外，公司会另外发一笔奖金。/Gōngzī zhī wài, gōngsī huì lìngwài fā yī bǐ jiǎngjīn/ Ngoài lương ra, công ty sẽ phát thêm một khoản tiền thưởng. 这家餐厅菜很好吃，另外，环境也很不错。/Zhè jiā cāntīng cài hěn hǎo chī, lìngwài, huánjìng yě hěn bùcuò/ Nhà hàng này đồ ăn rất ngon, thêm vào đó, không gian cũng rất tuyệt.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '首先…其次… /shǒuxiān… qícì…/', 'Dùng trong văn viết, biểu thị trình tự (trước hết, sau đó).', '不管以后做什么工作，你首先应该有一个好身体 /Bùguǎn yǐhòu zuò shénme gōngzuò, nǐ shǒuxiān yīnggāi yǒu yī gè hǎo shēntǐ/ Dù sau này làm công việc gì, bạn trước hết nên có một sức khỏe tốt.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '不管 /bùguǎn/', 'Liên từ, biểu thị trong bất kỳ tình huống nào (không quan tâm đến), thường dùng với “还/或是” hoặc các đại từ nghi vấn.', '山东不管做什么事都非常认真. /Tóngxué bùguǎn zuò shénme shì dōu fēicháng rènzhēn/ Tiểu Vương bất kể làm việc gì cũng rất nghiêm túc.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '以为 /yǐwéi/', 'Dùng để diễn tả người nói nghĩ hoặc tin rằng một sự việc là đúng, nhưng thực tế lại không đúng như vậy.', '我以为今天的会议室里一个人都没有 /Wǒ yǐwéi jīntiān de huìyì shì lǐ yī gè rén dōu méi yǒu/ Tôi tưởng rằng trong phòng họp hôm nay không có một người nào.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '原来 /yuánlái/', 'thể hiện sự phát hiện, nhận ra sự thật (với ngữ khí ngạc nhiên) hoặc chỉ trạng thái ban đầu, nguyên gốc của sự vật. Có thể dùng như phó từ hoặc hình dung từ (tính từ).', '原来是你！我还以为是小王呢。/Yuánlái shì nǐ! Wǒ hái yǐwéi shì Xiǎo Wáng ne/ Thì ra là bạn! Tôi cứ tưởng là Tiểu Vương. 我们还是按原来的计划进行吧。/Wǒmen háishì àn yuánlái de jìhuà jìnxíng ba/Chúng ta vẫn cứ theo kế hoạch ban đầu mà tiến hành đi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '并 /bìng/', 'Phó từ, dùng trước phủ định (不/没 (有)/无), có tác dụng nhấn mạnh ngữ khí phủ định,.', '我以为做生意很简单，后来才发现其实并不容易 /Wǒ yǐwéi zuò shēngyi hěn jiǎndān, hòulái cái fāxiàn qíshí bìng bù róngyì/ Tôi tưởng kinh doanh rất đơn giản, sau này mới phát hiện ra thực ra hoàn toàn không dễ dàng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '按照 /ànzhào/', 'Giới từ: theo, căn cứ vào.', '按照经验，这个问题应该很快解决，请大家放心 /Ànzhào jīngyàn, zhège wèntí yīnggāi hěn kuài jiějué, qǐng dàjiā fàngxīn/ Theo kinh nghiệm, vấn đề này nên sớm được giải quyết, mọi người yên tâm.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '甚至 /shènzhì/', 'Phó từ, nhấn mạnh trường hợp cực đoan hoặc là cuối cùng (thậm chí).', '这个房子离公司也不远，你可以坐公共汽车甚至可以骑自行车上班 /Zhège fángzi lí gōngsī yě bù yuǎn, nǐ kěyǐ zuò gōnggòng qìchē shènzhì');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '肯定 /kěndìng/', 'Phó từ: biểu thị mức độ chắc chắn cao, khẳng định rằng một việc nhất định sẽ xảy ra hoặc là đúng. Hình dung từ: thể hiện sự khẳng định, đồng ý hoặc xác nhận đối với một ý kiến hay sự việc.', '你放心吧，我肯定按时到。/Nǐ fàngxīn ba, wǒ kěndìng ànshí dào/ Bạn yên tâm đi, tôi nhất định sẽ đến đúng giờ. 请给我一个肯定的答复，是“去”还是“不去 /Qǐng gěi wǒ yī gè kěndìng de dáfù, shì “qù” háishì “bù qù”/ Hãy cho tôi một câu trả lời dứt khoát/rõ ràng, là "đi" hay "không đi"?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '再说 /zàishuō/', 'Động từ: Gác lại Liên từ (biểu thị bổ sung thêm sự việc).', '这个问题再说吧，我们先讨论紧急的。/Zhège wèntí xiān zàishuō ba, wǒmen xiān tǎo lùn jǐn jí de/ Vấn đề này gác lại đã, chúng ta hãy thảo luận việc khẩn cấp trước. 现在下着大雨，再说你又没带伞，就别出去了。/Xiànzài xià zhe dàyǔ, zàishuō nǐ yòu méi dài sǎn, jiù bié chū qù le/ Bây giờ trời đang mưa to, hơn nữa bạn lại không mang ô, đừng đi ra ngoài nữa.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '实际/实际上 /shíjì/shíjìshang/', 'Danh từ (thực tế) Hình dung từ (chân thật) Phó từ (trên thực tế),.', '理论要结合实际。/Lǐlùn yào jiéhé shíjì/ Lý thuyết phải kết hợp với thực tế. 请告诉我你的实际年龄。/Qǐng gàosu wǒ nǐ de shíjì niánlíng/ Hãy cho tôi biết tuổi thật của bạn. 他说自己很忙，实际上他只是在玩游戏。/Tā shuō zìjǐ hěn máng, shíjìshang tā zhǐshì zài wán yóuxì/ Anh ấy nói mình rất bận, nhưng thực ra/thực tế anh ấy chỉ đang chơi game.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '对…来说 /duì… láishuō/', 'Giới từ, biểu thị thái độ đối với một đối tượng nào đó.', '对一个女人来说，漂亮、聪明都很重要，但其实更重要的是快乐. /Duì yī gè nǚrén láishuō, piàoliang, cōngmíng dōu hěn zhòngyào, dàn qíshí gèng zhòngyào de shì kuàilè/ Đối với một người phụ nữ mà nói, xinh đẹp, thông minh đều quan trọng, nhưng thực ra quan trọng hơn là niềm vui.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '尤其 /yóuqí/', 'Phó từ dùng để nhấn mạnh, biểu thị mức độ hoặc tính chất của một sự việc/sự vật cao hơn, đặc biệt hơn những cái khác trong cùng một phạm trù.', '你女儿真可爱，长得真像你，尤其是眼睛 /Nǐ nǚ''ér zhēn kě''ài, zhǎng de zhēn xiàng nǐ, yóuqí shì yǎnjīng/ Con gái bạn thật đáng yêu, lớn lên rất giống bạn, đặc biệt là đôi mắt.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '竟然 /jìngrán/', 'phó từ cảm thán, dùng để biểu thị sự việc xảy ra trái với dự đoán, lẽ thường hoặc ngoài ý muốn,', '他三年没练钢琴，竟然弹得还这么好。 /Tā sān nián méi liàn gāngqín, jìngrán tán de hái zhème hǎo/ Anh ấy ba năm không luyện piano, không ngờ vẫn chơi hay đến thế.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '倍 (bèi)', 'lượng từ, dùng để biểu thị số lần (bội số) khi so sánh về số lượng, mức độ hoặc kích thước', '我的工资比五年前高了五倍。 /Wǒ de gōngzī bǐ wǔ nián qián gāo le wǔ bèi/ Lương của tôi cao gấp năm lần (so với) năm năm trước.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '值得 /zhíde/', 'động từ, biểu thị việc gì đó có giá trị, xứng đáng, đáng (để bỏ công sức, thời gian, tiền bạc...).', '这本书很值得一读。 /Zhè běn shū hěn zhíde yì dú/ Cuốn sách này rất đáng đọc.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '其中 /qízhōng/', 'danh từ (đôi khi được phân loại là cụm từ chỉ định), có nghĩa là trong số đó, trong đó, bên trong đó.', '我们班有二十名学生，其中 十名是女生。 /Wǒmen bān yǒu èrshí míng xuéshēng, qízhōng shí míng shì nǚshēng/ Lớp chúng tôi có 20 học sinh, trong đó có 10 bạn là nữ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '(在)…下 ((zài)… xià)', 'Cấu trúc giới từ/danh từ, biểu thị điều kiện, tình huống cho một sự việc xảy ra.', '在老师和同学们的帮助下，他的汉语提高得非常快 /Zài lǎoshī hé tóngxuémen de bāngzhù xià, tā de Hànyǔ tígāo de fēicháng kuài/ Dưới sự giúp đỡ của thầy cô và các bạn, tiếng Hán của anh ấy tiến bộ rất nhanh');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '估计 /gūjì/', 'Động từ (biểu thị đoán, phán đoán) Danh từ (biểu thị sự ước tính, phỏng chừng).', '你估计 这个项目多久能完成？ /Nǐ gūjì zhège xiàngmù duōjiǔ néng wánchéng/ Bạn ước tính dự án này bao lâu thì hoàn thành? 根据市场估计，这款产品的需求量很大。 /Gēnjù shìchǎng gūjì, zhè kuǎn chǎnpǐn de xūqiú liàng hěn dà/ Theo ước tính của thị trường, nhu cầu cho sản phẩm này rất lớn.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '来不及 /láibují/', 'bổ ngữ khả năng có nghĩa không kịp, không còn đủ thời gian để làm việc gì đó.', '事情发生得太突然，我来不及通知你。 /Shìqing fāshēng de tài tūrán, wǒ láibují tōngzhī nǐ/ Sự việc xảy ra quá đột ngột, tôi không kịp báo cho bạn.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '离合词重叠 /líhécí chóngdié/', 'Cấu trúc lặp lại của động từ ly hợp (thường là dạng AAB), biểu thị thời gian ngắn, thử nghiệm, hoặc thư giãn.', '学习累了，我们出去散散步吧。 /Xuéxí lèi le, wǒmen chūqù sàn san bù ba/ Học mệt rồi, chúng ta ra ngoài đi dạo một chút đi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '要是 /yàoshi/', 'Liên từ dùng để giả định một điều kiện. Cấu trúc cơ bản: “要是” + [tình huống giả định] ，就 + [kết quả/hành động sẽ xảy ra].', '要是明天下雨，我们就不去公园了。 /Yàoshi míngtiān xià yǔ, wǒmen jiù bù qù gōngyuán le/ Nếu ngày mai trời mưa, thì chúng tôi sẽ không đi công viên nữa.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '既…又/也/还… (jì… yòu/yě/hái…)', 'Liệt kê hai (hoặc nhiều) đặc điểm, tính chất hoặc trạng thái cùng tồn tại về một sự vật, sự việc. Cấu trúc: 既 + [Tính chất 1] + 又/也/还 + [Tính chất 2]', '她既聪明又漂亮。 /Tā jì cōngmíng yòu piàoliang/ Cô ấy vừa thông minh vừa xinh đẹp.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '使 /shǐ/', 'Động từ cầu khiến, làm cho / khiến cho một ai/cái gì thay đổi trạng thái hoặc thực hiện một hành động. Cấu trúc phổ biến: A + 使 + B + [hành động/thay đổi]', '这个消息使大家很高兴。 /Zhège xiāoxi shǐ dàjiā hěn gāoxìng/ Tin tức này khiến mọi người rất vui.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '只要…就… /zhǐyào… jiù…/', 'Là cặp liên từ biểu thị điều kiện cần, chỉ cần thỏa mãn một điều kiện duy nhất/tối thiểu đó thì kết quả chắc chắn xảy ra. Công thức cơ bản: 只要 + [Điều kiện cần], 就 + [Kết quả/Động tác sẽ xảy ra]', '你只要想去，我就带你去。 /Nǐ zhǐyào xiǎng qù, wǒ jiù dài nǐ qù/ Chỉ cần bạn muốn đi, thì tôi sẽ đưa bạn đi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '可不是 /kě bú shì/', 'Phó từ, biểu thị tán thành hoặc phụ họa ý kiến của người khác.', '这个电影可不是很好看吗？我都看了三遍了。 /Zhège diànyǐng kě bú shì hěn hǎokàn ma? Wǒ dōu kànle sān biàn le/ Chẳng phải là bộ phim này rất hay sao? Tôi xem đến ba lần rồi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '因此 /yīncǐ/', 'Liên từ, biểu thị nguyên nhân, vì vậy.', '做好小事是完成大事的第一步，因此，件件小事都应该被看成是一次 学习的机会. /Zuò hǎo xiǎo shì shì wánchéng dà shì de dì yī bù, yīncǐ, jiànjiàn xiǎo shì dōu yīnggāi bèi kànchéng shì yī cì xuéxí de jīhuì/');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '往往 /wǎngwǎng/', 'Phó từ, biểu thị kinh nghiệm trong quá khứ, thường xảy ra trong một điều kiện nhất định.', '他往往工作到深夜。 /Tā wǎngwǎng gōngzuò dào shēnyè/ Anh ấy thường làm việc đến tận khuya.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '难道 /nándào/', 'Phó từ, dùng trong câu hỏi, biểu thị ngữ khí nghi vấn nhấn mạnh (chẳng lẽ).', '难道你花了好几个小时才做完这个题. /Nándào nǐ huā le jǐ ge xiǎoshí cái zuò wán zhège tí/ Chẳng lẽ bạn đã mất mấy tiếng đồng hồ mới làm xong câu này.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '通过 /tōngguò/', 'Giới từ: chỉ cách thức hoặc phương tiện để đạt được mục đích (thông qua, bằng cách). Động từ: chỉ hành động đi qua một nơi hay một không gian.', '通过努力，任何困难都会解决. /Tōngguò nǔlì, rènhé kùnnan dōu huì jiějué/ Thông qua nỗ lực, bất kỳ khó khăn nào cũng sẽ được giải quyết. 这条街只能通过. /Zhè tiáo jiē zhǐ néng tōngguò/ Con phố này chỉ có thể đi qua.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '可是 /kěshì/', 'Liên từ, dùng ở đầu vế câu sau, biểu thị chuyển ý, tương phản (nhưng mà).', '我本来想当律师，可是后来我发现自己对新闻更感兴趣. /Wǒ běnlái xiǎng dāng lǜshī, kěshì hòulái wǒ fāxiàn zìjǐ duì xīnwén gèng gǎnxìngqù/ Tôi vốn định làm luật sư, nhưng sau này tôi phát hiện bản thân lại hứng thú hơn với báo chí.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '结果 /jiéguǒ/', 'Danh từ: Kết quả, hậu quả, thành quả cuối cùng. Liên từ: Cuối cùng, rốt cuộc, kết cục là. Dùng để nối hai phân câu, vế sau là kết quả/ tình huống cuối cùng xảy ra (thường có chút bất ngờ hoặc khác với dự tính ban đầu).', '比赛的结果将在晚上八点公布。 Bǐsài de jiéguǒ jiāng zài wǎnshang bā diǎn gōngbù. Kết quả của trận đấu sẽ được công bố lúc 8 giờ tối. 我们找了半天钥匙，结果发现它就在口袋里。 Wǒmen zhǎo le bàntiān yàoshi, jiéguǒ fāxiàn tā jiù zài kǒudài lǐ. Chúng tôi tìm chìa khóa mãi, rốt cuộc phát hiện nó nằm ngay trong túi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '确实 /quèshí/', 'Phó từ, biểu thị khách quan và khẳng định (quả thực, thật sự).', '确实，这个方案更节省成本。 /Quèshí, zhège fāng''àn gèng jiéshěng chéngběn/ Quả thực, phương án này tiết kiệm chi phí hơn.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '在…看来 /zài… kànlái/', 'Thành ngữ chêm xen, biểu thị quan điểm, cách nhìn cá nhân.', '在很多人看来，听流行音乐是年轻人的爱好. /Zài hěn duō rén kànlái, tīng liúxíng yīnyuè shì niánqīng rén de àihǎo/ Theo quan điểm của nhiều người, nghe nhạc pop là sở thích của người trẻ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '由于 /yóuyú/', 'Liên từ/Giới từ, biểu thị nguyên nhân, bởi vì,.', '由于各种原因，我们不得不改变原来的计划. /Yóuyú gèzhǒng yuányīn, wǒmen bù dé bù gǎibiàn yuánlái de jìhuà/ Do nhiều nguyên nhân khác nhau, chúng tôi buộc phải thay đổi kế hoạch ban đầu.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '连…也/都… /lián… yě/dōu…/', 'Liên từ, dùng để nhấn mạnh một trường hợp (ngay cả... cũng/còn...).', '如果你连自己都不喜欢，又怎么能让别人喜欢你呢? /Rúguǒ nǐ lián zìjǐ dōu bù xǐhuān, yòu zěnme néng ràng biérén xǐhuān nǐ ne/ Nếu bạn ngay cả bản thân mình còn không thích, làm sao có thể khiến người khác thích bạn?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '否则 /fǒuzé/', 'Liên từ, nghĩa là "nếu không (thì)", chỉ ra kết quả tiêu cực nếu vế trước không xảy ra,.', '看来要考好，要认真复习...否则会做的题也没时间做了. /Kàn lái yào kǎo hǎo, yào rènzhēn fùxí... fǒuzé huì zuò de tí yě méi shíjiān zuò le/ Xem ra muốn thi tốt, phải ôn tập nghiêm túc... nếu không thì đề đã làm được cũng không kịp thời gian.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '无论 /wúlùn/', 'Liên từ, biểu thị bất kể điều kiện nào, kết quả cũng không thay đổi, thường dùng với cấu trúc “无论……都/也 …”.', '无论你 去不去，都请通知我一声。 /Wúlùn nǐ qù bu qù, dōu qǐng tōngzhī wǒ yīshēng/ Bất kể bạn có đi hay không, cũng hãy thông báo cho tôi một tiếng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '然而 /rán''ér/', 'Liên từ, dùng ở đầu vế câu sau, biểu thị chuyển ý (nhưng, song), thường dùng trong văn viết,.', '他虽然失败了很多次，然而一直没有放弃. /Tā suīrán shībài le hěnduō cì, rán''ér yīzhí méi yǒu fàngqì/ Mặc dù anh ấy thất bại nhiều lần, nhưng vẫn không từ bỏ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '同时 /tóngshí/', 'Liên từ/Danh từ, biểu thị hai hành động xảy ra đồng thời hoặc có quan hệ liên kết.', '我们要发展经济，同时也必须保护环境。 /Wǒmen yào fāzhǎn jīngjì, tóngshí yě bìxū bǎohù huánjìng/ Chúng ta cần phát triển kinh tế, đồng thời cũng phải bảo vệ môi trường.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '并且 /bìngqiě/', 'Liên từ, dùng để nối các động từ hoặc tính từ song song, biểu thị hai hoặc nhiều tính chất cùng tồn tại (hơn nữa, đồng thời).', '这房子家具全...并且价格也便宜，真的恨值得考虑. /Zhè fángzi jiājù quán... bìngqiě jiàgé yě piányi, zhēn de hěn zhíde kǎolǜ/ Căn nhà này đầy đủ nội thất... hơn nữa giá cả cũng rẻ, thực sự đáng để cân nhắc.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '再…也…/zài… yě…/', 'Cấu trúc biểu thị giả định, "再" đứng trước động từ/tính từ, ý nghĩa "dù thế nào đi nữa".', '事情已经发生了，你再后悔也无法改变，别伤心了. /Shìqing yǐjīng fāshēng le, nǐ zài hòuhuǐ yě wúfǎ gǎibiàn, bié shāngxīn le/ Chuyện đã xảy ra rồi, bạn có hối hận nữa cũng không thể thay đổi, đừng buồn nữa.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '对于 /duìyú/', 'Giới từ, biểu thị đối tượng của thái độ hoặc tình huống nào đó,.', '对于这件事，我跟大家的看法不同. /Duìyú zhè jiàn shì, wǒ gēn dàjiā de kànfǎ bù tóng/ Đối với việc này, quan điểm của tôi khác với mọi người/');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '名量词重叠 /liàngcí chóngdié/', 'Cấu trúc lặp lại lượng từ (thường là dạng “AA”), biểu thị ý nghĩa “mỗi”.', '人人都会使用语言，但是怎么用语言把话说好却是一门艺术. /Rénrén dōu huì shǐyòng yǔyán, dànshì zěnme yòng yǔyán bǎ huà shuō hǎo què shì yī mén yìshù/ Mỗi người đều biết dùng ngôn ngữ, nhưng làm thế nào để nói hay lại là một nghệ thuật.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '相反 /xiāngfǎn/', 'Tính từ: Miêu tả trạng thái đối lập giữa hai sự vật/tính chất. Liên từ: Dùng để nối và giới thiệu một ý/phân câu trái ngược với ý trước đó, thường dịch là "ngược lại", "trái lại".', '这场危机不但没有削弱团队，相反，让大家更加团结了。 /Zhè chǎng wēijī bùdàn méiyǒu xuēruò tuánduì, xiāngfǎn, ràng dàjiā gèngjiā tuánjié le/ Cuộc khủng hoảng này không những không làm suy yếu đội ngũ, mà ngược lại, còn khiến mọi người thêm đoàn kết. 我们的观点完全相反。 /Wǒmen de guāndiǎn wánquán xiāngfǎn/ Quan điểm của chúng tôi hoàn toàn trái ngược.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '大概 /dàgài/', 'Phó từ, biểu thị ước đoán số lượng hoặc đánh giá, mức độ chính xác không cao.', '从这儿到机场，大概需要一个小时。 /Cóng zhèr dào jīchǎng, dàgài xūyào yī gè xiǎoshí/ Khoảng một tiếng đồng hồ là từ đây đến sân bay.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '偶尔 /ǒu''ěr/', 'Phó từ, biểu thị tần suất xảy ra rất ít, thỉnh thoảng,.', '他平时很忙，只是偶尔来看看父母。 /Tā píngshí hěn máng, zhǐshì ǒu''ěr lái kànkan fùmǔ/ Anh ấy bình thường rất bận, chỉ thỉnh thoảng mới về thăm bố mẹ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '由 /yóu/', 'Giới từ, dùng để chỉ người chịu trách nhiệm về một việc nào đó,.', '按照规定，这件事应该由王夫夫负责. /Ànzhào guīdìng, zhè jiàn shì yīnggāi yóu Wáng fūfū fùzé/ Theo quy định, việc này nên do ông Vương phụ trách');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '随着 /suízhe/', 'Giới từ, biểu thị điều kiện để một sự việc khác xảy ra (cùng với, theo)', '随着社会的发展，京剧也在改变. /Suízhe shèhuì de fāzhǎn, Jīngjù yě zài gǎibiàn/ Cùng với sự phát triển của xã hội, Kinh kịch cũng đang thay đổi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '够 /gòu/', 'Động từ: Đủ, đạt đến mức cần thiết về số lượng, tiêu chuẩn hoặc thời gian. Phó từ: Đủ, đến một mức độ nhất định (thường biểu thị mức độ cao, có thể đã vượt quá mong đợi)', '这些钱够我们旅行吗？ /Zhèxiē qián gòu wǒmen lǚxíng ma/ Số tiền này có đủ cho chúng tôi đi du lịch không? 你今天看起来够漂亮的！ /Nǐ jīntiān kàn qǐlái gòu piàoliang de/ Hôm nay trông bạn thật là xinh đẹp!');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '以 /yǐ/', 'Giới từ: Dựa vào, dùng, lấy... làm... (Biểu thị công cụ, phương thức, căn cứ) Cấu trúc: 以 + Danh từ (+ 为/而...)', '我们应以事实为根据，不要轻信谣言。 /Wǒmen yīng yǐ shìshí wéi gēnjù, bú yào qīngxìn yáoyán/ Chúng ta nên lấy sự thật làm căn cứ, đừng dễ tin lời đồn.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '既然 /jìrán/', 'Liên từ, dùng ở vế câu trước, ý nghĩa "vì sự thật đã là như vậy rồi". Vế câu sau thường dùng “就”, “也”, “还”.', '既然大家都同意这个方案，我们就马上开始吧。 /Jìrán dàjiā dōu tóngyì zhège fāng''àn, wǒmen jiù mǎshàng kāishǐ ba/ Vì mọi người đều đồng ý với phương án này rồi, chúng ta hãy bắt đầu ngay đi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '于是 /yúshì/', 'Liên từ, dùng ở vế câu sau của câu phức, biểu thị sự việc tiếp theo xảy ra sau sự việc đã nêu ở vế trước,.', '听爷爷奶奶说，我妹妹出生那天，下了场大雪，于是我爸妈就给她取名 叫夏雪. /Tīng yéyé nǎinai shuō, wǒ mèimei chūshēng nà tiān, xià le chǎng dà xuě, yúshì wǒ bà mā jiù gěi tā qǔ míng jiào Xiàxuě/ Nghe ông bà nói... thế là bố mẹ tôi đặt tên em ấy là Hạ Tuyết.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '想起来 /xiǎngqǐlái/', 'Động từ + bổ ngữ xu hướng, biểu thị sự ghi nhớ một điều gì đó từ trước đó.', '听到这个声音，我一下子想不起来是谁了. /Tīng dào zhège shēngyīn, wǒ yī xiàzi xiǎng bù qǐlái shì shuí le/ Nghe giọng này, tôi nhất thời không nhớ ra là ai.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '千万 /qiānwàn/', 'Một phó từ nhấn mạnh sự khuyên bảo hoặc cảnh báo, thường dịch là "nhất định phải/đừng"', '过马路时千万要小心，不要闯红灯。 /Guò mǎlù shí qiānwàn yào xiǎoxīn, bú yào chuǎng hóngdēng/ Khi sang đường nhất định phải cẩn thận, đừng vượt đèn đỏ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '恐怕 (kǒngpà)', 'Động từ: E rằng, lo sợ rằng. Phó từ: Dùng để biểu thị một phán đoán, ước lượng với thái độ dè dặt, không chắc chắn, thường kèm theo lo lắng hoặc tiên đoán về kết quả không mong muốn.', '我恐怕此事會帶來不良後果。 /Wǒ kǒngpà cǐ shì huì dàilái bùliáng hòuguǒ/ Tôi e rằng việc này sẽ mang lại hậu quả không tốt. 看這天氣，恐怕要下大雨了。 /Kàn zhè tiānqì, kǒngpà yào xià dàyǔ le/ Nhìn thời tiết thế này, có lẽ sắp có mưa to rồi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '到底 /dàodǐ/', 'Phó từ, dùng trong câu hỏi nghi vấn/có đại từ nghi vấn, nhấn mạnh ngữ khí truy vấn (rốt cuộc, cuối cùng).', '你到底想说什么？ /Nǐ dàodǐ xiǎng shuō shénme/ Bạn rốt cuộc muốn nói gì?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '拿…来说 /ná… láishuō/', 'Cấu trúc dùng để đưa ra sự vật/tình huống làm ví dụ.', '学习语言需要耐心。拿学汉语来说，每天坚持练习才能进步。 /Xuéxí yǔyán xūyào nàixīn. Ná xué hànyǔ láishuō, měitiān jiānchí liànxí cáinéng jìnbù/ Học ngôn ngữ cần sự kiên nhẫn. Lấy việc học tiếng Trung mà nói, phải kiên trì luyện tập hàng ngày mới tiến bộ được.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '敢 /gǎn/', 'Động từ năng nguyện, biểu thị có dũng khí làm một việc gì đó,.', '我们应该把那些敢说真话的人当镜子. /Wǒmen yīnggāi bǎ nà xiē gǎn shuō zhēnhuà de rén dāng jìngzi/ Chúng ta nên coi những người dám nói sự thật như một tấm gương.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '倒 /dào/', 'Phó từ, biểu thị trái ngược hoặc ngoài ý muốn.', '你说他笨？我倒觉得他很聪明。');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '趟 /tàng/', 'Lượng từ, biểu thị số lần đi và về.', '上个月我去了趟北京动物园. /Shàng gè yuè wǒ qù le yī tàng Běijīng dòngwùyuán/ Tháng trước tôi đã đi một chuyến đến Vườn thú Bắc Kinh.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '为了……而…… /wèile… ér…/', 'Cấu trúc liên từ, vế câu trước chỉ mục đích, vế câu sau chỉ hành vi.', '我们不应该为了钱而工作. Wǒmen bù yīnggāi wèile qián ér gōngzuò/ Chúng ta không nên vì tiền mà làm việc.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '仍然 /réngráng/', 'Phó từ, biểu thị ý trái ngược, trái với dự kiến hoặc ngoài ý muốn.', '这件衣服好看倒好看，就是太贵了。 /Zhè jiàn yīfu hǎokàn dào hǎokàn, jiùshì tài guì le/ Bộ quần áo này đẹp thì đẹp thật, chỉ có điều quá đắt.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '是否 /shìfǒu/', 'Phó từ, Biểu thị tình trạng, trạng thái hoặc hành động tiếp tục duy trì, không thay đổi so với trước.', '虽然遇到了困难，但他仍然非常乐观。 /Suīrán yù dào le kùnnán, dàn tā réngrán fēicháng lèguān/ Tuy gặp khó khăn, nhưng anh ấy vẫn rất lạc quan.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '受不了 /shòubuliǎo/', 'Bổ ngữ khả năng, biểu thị không thể chịu đựng được (áp lực, nỗi đau, tình huống).', '不过天天对着电脑，眼睛实在受不了. /Búguò tiāntiān duì zhe diànnǎo, yǎnjīng shízài shòu bù liǎo/ Nhưng ngày nào cũng đối diện với máy tính, mắt thực sự không chịu nổi nữa.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '接着 /jiēzhe/', 'Phó từ: Biểu thị một hành động hoặc sự việc xảy ra ngay sau một hành động/sự việc khác, hoặc được nối tiếp một cách logic.', '他吃完晚饭，接着又开始工作了。 /Tā chī wán wǎnfàn, jiēzhe yòu kāishǐ gōngzuò le/ Anh ấy ăn tối xong, tiếp theo lại bắt đầu làm việc.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '除此以外 /chúcǐ yǐwài/', 'Phó từ, tương đương với "ngoài cái này ra" (chỉ nội dung đã nói ở vế trước), thường dùng trong văn viết.', '他和我弟弟一天出生...除此以外几乎再找不到其他共同点. /Tā hé wǒ dìdi yī tiān chūshēng... chú cǐ yǐwài jīhū zài zhǎo bù dào qítā gòngtóng diǎn/ Tôi và em trai sinh cùng ngày... ngoài điều đó ra thì hầu như không tìm thấy điểm chung nào khác.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '把…叫做… /bǎ… jiàozuò…/', 'Cấu trúc dùng để gọi tên một vật thể hoặc hiện tượng.', '在中国，我们把父亲的爸爸叫做“爷爷”。 /Zài zhōngguó, wǒmen bǎ fùqīn de bàba jiàozuò “yéye”/ Ở Trung Quốc, chúng tôi gọi bố của bố là "ông nội".');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '总的来说 /zǒngde láishuō/', 'Dùng làm thành phần chêm xen, dùng để tóm tắt hoặc đánh giá (nói chung).', '我对这个方案的看法，总的来说，是支持的，不过还有一些细节需要完 善。 /Wǒ duì zhège fāng''àn de kànfǎ, zǒngde láishuō, shì zhīchí de, búguò hái yǒu yīxiē xìjié xūyào wánshàn/ Ý kiến của tôi về phương án này, nhìn chung, là ủng hộ, tuy nhiên vẫn còn một số chi tiết cần hoàn thiện.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '在于 /zàiyú/', 'Động từ, dùng trong văn viết, dùng để chỉ bản chất, là trọng tâm, là mấu chốt.', '选择职业的关键在于兴趣. /Xuǎnzé zhíyè de guānjiàn zàiyú xìngqù/ Điều cốt lõi khi chọn nghề nằm ở sở thích');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', 'Cấu trúc: Động từ 1 + 着 + Động từ 1 + 着 + (，就/却/ 忽然…) + Hành động/Trạng thái mới', 'Cấu trúc này mô tả một hành động đang kéo dài thì đột nhiên hoặc tự nhiên dẫn đến một kết quả, thay đổi hoặc một hành động khác.', '她看着看着书，就睡着了。 Tā kànzhe kànzhe shū, jiù shuì zháo le. Cô ấy đang xem sách, thì ngủ gật mất rồi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '一…就… /yī… jiù…/', 'Cấu trúc biểu thị hai sự việc xảy ra liên tiếp hoặc biểu thị điều kiện/kết quả.', '女儿一回来就告诉她这个好消息. /Nǚ''ér yī huílái jiù gàosu tā zhège hǎo xiāoxi/ Con gái vừa về thì lập tức nói cho cô ấy tin vui này.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '究竟 /jiūjìng/', 'Phó từ, dùng trong câu hỏi nghi vấn/có đại từ nghi vấn, nhấn mạnh ngữ khí truy vấn (rốt cuộc), thường dùng trong văn viết.', '究竟哪个季节去丽江旅游比较好. /Jiūjìng nǎ ge jìjié qù Lìjiāng lǚyóu bǐjiào hǎo/ Rốt cuộc đi du lịch Lệ Giang vào mùa nào là tốt nhất?');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', '起来 /qǐlái/', 'Động từ/Bổ ngữ xu hướng, biểu thị hành động bắt đầu/tiếp tục, hoặc biểu thị đánh giá cá nhân.', '你先把桌子上的东西收拾起来. /Nǐ xiān bǎ zhuōzi shàng de dōngxi shōushi qǐlái// Bạn dọn dẹp đồ trên bàn trước đi. 这件事说起来容易，做起来难。 /Zhè jiàn shì shuō qǐlái róngyì, zuò qǐlái nán/ Việc này nói ra thì dễ, làm thì mới khó.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 4', 'Cấu trúc: 动词+ 起 (dòngcí + qǐ)', 'Cấu trúc này nhấn mạnh sự khởi điểm của hành động hướng vào một đối tượng cụ thể. Tân ngữ thường là nội dung của cuộc nói chuyện, câu hỏi, hoặc đối tượng của ký ức, cảm xúc.', '他偶然说起了学生时代的往事。 /Tā ǒurán shuō qǐ le xuéshēng shídài de wǎngshì/ Anh ấy tình cờ nhắc đến chuyện cũ thời học sinh.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '如何 /Rúhé', 'Đại từ', 'Dùng để hỏi phương thức/cách thức giải quyết vấn đề, thường dùng ở cuối câu để trưng cầu ý kiến hoặc hỏi thăm tình hình.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '靠 /Kào/', 'Động từ/Danh từ', 'Là động từ, nghĩa là dựa vào, tựa vào để chống đỡ trọng lượng; nhờ, dựa vào ai đó mới đạt được lợi ích; gần kề, kế liền.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '居然 /Jūrán/', 'Phó từ', 'Biểu thị sự không ngờ đến, bất ngờ, ngạc nhiên ("lại có thể", "lại").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '以来 /Yǐlái/', 'Danh từ', 'Biểu thị một khoảng thời gian từ một thời điểm nào đó trong quá khứ đến thời điểm hiện tại.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '临 /Lín/', 'Động từ/Giới từ', 'Là động từ, có nghĩa là dựa sát, kề, kế. Là giới từ ("临.....（时/前）"), biểu thị sắp đến thời gian phát sinh của một hành động.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '立刻 /Lìkè/', 'Phó từ', 'Biểu thị sự ngay lập tức, nhấn mạnh một hành động nối tiếp hành động phát sinh ngay trước đó.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '各自 /Gèzì/', 'Đại từ', 'Chỉ bản thân một người hoặc chỉ một trong những phương diện của bản thân, thường cùng với đối tượng được nhắc đến làm chủ ngữ, định ngữ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '勿 /Wù/', 'Phó từ', 'Ngôn ngữ viết, biểu thị sự cấm đoán, không cho phép hoặc can ngăn ("chớ, đừng"), tương đương với “不要”.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '包括 /Bāokuò/', 'Động từ', 'Biểu thị bao hàm các bộ phận. Nhấn mạnh một vài bộ phận, có tác dụng nêu ví dụ, bổ sung, giải thích.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '时刻 /Shíkè/', 'Danh từ/Phó từ', 'Danh từ: Biểu thị ở một vài thời điểm hoặc một đoạn thời gian. Phó từ: Biểu thị ý nghĩa mỗi thời mỗi khắc, thường xuyên (có thể lặp lại là “时时刻刻”).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '至今 /Zhìjīn/', 'Phó từ', 'Chỉ thời gian, dùng để nhấn mạnh một trạng thái, sự việc hoặc tình huống kéo dài liên tục từ một thời điểm trong quá khứ cho đến thời điểm hiện tại (thời điểm nói)');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '顶 /Dǐng/', 'Danh từ/Động từ/Lượng từ', 'Danh từ: Chỉ bộ phận cao nhất của con người hoặc vật thể. Động từ: Biểu thị động tác của đầu, hoặc đón lấy, chống lại (áp lực).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '······得+不 行 /De bùxíng/', 'Kết cấu', 'Biểu thị trình độ, mức độ cao, còn có thể dùng “······+得+ 很/不得了”.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '反而 /Fǎn''ér/', 'Phó từ', 'Đứng giữa hai câu, biểu thị sự tương phản với dự kiến ban đầu ("ngược lại").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '从而 /Cóng''ér/', 'Liên từ', 'Đứng giữa hai câu, câu trước biểu thị nguyên nhân/phương pháp, câu sau biểu thị kết quả/mục đích ("từ đó").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '于 /Yú/', 'Giới từ', 'Tương đương với “在、从、 对、向、比” (ở, từ, đối với, hướng về, so với).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '为 /Wéi/', 'Động từ', 'Có nghĩa là “成、成为” (thành, trở thành) Có nghĩa là “作为、算作” (làm, coi như).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '起来 /Qǐlái/', 'Động từ xu hướng', 'Dùng sau động từ: Biểu thị từ phân tán đến tập trung lại Biểu thị từ lộ rõ đến ẩn nấp, ẩn náu.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '替 /Tì/', 'Động từ/Giới từ', 'Là động từ: có nghĩa là "thay thế". Là giới từ: biểu thị “给、为” (cho ai, vì ai).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '说不定 /Shuōbudìn g/', 'Động từ/Phó từ', 'Là động từ: có nghĩa là "không thể nói rõ ràng, khẳng định" Là phó từ: biểu thị ước tính, có khả năng lớn ("biết đâu").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '似的 /Shìde/', 'Trợ từ', 'Trợ từ, đặt sau danh từ, biểu thị sự so sánh với một số sự vật, tình huống (thường dùng trong văn viết). Dùng trong cấu trúc “·····得+什么似的” mang ngữ khí khoa trương.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '纷纷 /Fēnfēn/', 'Tính từ/Phó từ', 'Tính từ: Mô tả (ngôn luận, vật rơi, rụng xuống) nhiều mà hỗn loạn. Phó từ: Biểu thị (nhiều người hoặc sự vật) liên tục tiếp diễn ("dồn dập, tới tấp, sôi nổi").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '瞎 /Xiā/', 'Động từ/Phó từ', 'Động từ: Nghĩa là "mắt không nhìn thấy" (mù). Phó từ: Biểu thị không có lí do, không có căn cứ hoặc khi làm một việc không có hiệu quả ("nói bừa, làm bừa").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '分别 /Fēnbié/', 'Động từ/Phó từ/Danh từ', 'Động từ: nghĩa là ly biệt, chia tay, xa cách. Phó từ: biểu thị riêng biệt, mỗi cái một. Danh từ: nghĩa là phân biệt, bất đồng, khác nhau.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '根 /Gēn/', 'Danh từ/Lượng từ', 'Danh từ: Chỉ bộ phận của thực vật sinh trưởng dưới lòng đất, hoặc nền móng, cơ sở, gốc rễ của sự vật. Lượng từ: Thường dùng cho vật dài và nhỏ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '便 /Biàn/', 'Phó từ', 'Nghĩa là 就 (“thì, là, đã”), thường dùng trong văn viết.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '倒 /Dào/', 'Phó từ', 'Biểu thị tương phản, trái ngược với tình huống thông thường. Biểu thị không nghĩ đến. Biểu thị sự nhượng bộ (khẳng định trước, sau đó nói các phương diện khác). Biểu thị không nhẫn nại, bình tĩnh (dùng để hỏi hoặc hối thúc).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '······来 ······去 /Lái... Qù/', 'Kết cấu', 'Biểu thị sự lặp đi lặp lại nhiều lần của động tác, hai động từ đứng trước “来” và “去” thường là cùng một từ hoặc là từ gần nghĩa.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '要不 /Yàobù/', 'Liên từ', 'Giống với “要不然”, biểu thị nếu không như thế này, thì kết quả sẽ như dưới đây. Có nghĩa là vẫn còn một sự lựa chọn khác ("hay là").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '算 /Suàn)/', 'Động từ', 'Có nghĩa là “认作，当做” (xem như, coi như). Đằng sau có thể đi với “了” biểu thị “作罢，不再计较” (bỏ đi, không tính toán nữa).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '作为 /Zuòwéi/', 'Động từ/Giới từ', 'Động từ: Có nghĩa là “看做， 认为是·····” (xem là, coi là, cho rằng). Giới từ: Dùng để chỉ ra, dẫn ra thân phận của một người hoặc tính chất của sự vật ("với tư cách là").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '曾经 /Céngjīng/', 'Phó từ', 'Biểu thị hành động hoặc tình huống đã từng xảy ra hoặc từng phát sinh.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '毕竟 /Bìjìng/', 'Phó từ', 'Có nghĩa là rốt cuộc, cuối cùng Dùng để chỉ phần quan trọng nhất hoặc chính xác nhất, thường dùng cùng câu biểu thị “cho dù thế nào thì kết quả chính là như thế này”.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '逐渐 /Zhújiàn/', 'Phó từ', 'Chỉ trình độ, số lượng tăng hoặc giảm một chút ("dần dần").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '或许 /Huòxǔ/', 'Phó từ', 'Có nghĩa là có lẽ, có khả năng ("có lẽ").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '来/过来 /Lái/Guòlái /', 'Động từ xu hướng', 'Dùng sau động từ (ví dụ: "醒 ") biểu thị chuyển tiếp từ lúc ngủ đến lúc tỉnh, hoặc quay về trạng thái lúc ban đầu/bình thường. Có thể dùng trong cấu trúc phủ định (动词 + 得/不 + 过 来).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '所 /Suǒ/', 'Trợ từ/Lượng từ', 'Trợ từ: Đứng trước động từ, dùng để chỉ ra sự vật (thường làm định ngữ, chủ ngữ...). Dùng trong cấu trúc “有/无+ 所+ động từ” Lượng từ: Dùng với chỗ ở, nơi ở, cơ cấu (ví dụ: trường học).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '相当 /Xiāngdān g/', 'Động từ/Phó từ', 'Động từ: Biểu thị hai phương diện (số lượng, điều kiện...) tương đương, ngang bằng nhau. Phó từ: Biểu thị trình độ, mức độ tương đối cao ("khá, tương đối").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '数 /Shǔ/Shù/', 'Động từ/Số từ', 'Động từ (shǔ): Biểu thị tra, đếm (số lượng). Dùng trong cấu trúc “数······（最）······” hoặc “（最）······的（要/就）数 ······” biểu thị so sánh (nhất). Số từ (shù): Có nghĩa là “几/ 几个” (vài, mấy), thường dùng trong văn viết.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '以及 /Yǐjí/', 'Liên từ', 'Dùng để nối cụm từ hoặc từ có quan hệ ngang bằng nhau, liên kết thành phần thường có sự phân biệt trước sau hoặc sự phân biệt chủ yếu và thứ yếu ("cũng như").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '程度 (Chéngdù)', 'Danh từ', 'Chỉ trình độ, mức độ hoặc cấp độ mà ở một vài phương diện đã đạt được.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '何况 /Hékuàng/', 'Liên từ', 'Dùng ngữ khí phản vấn, biểu thị cao hơn một mức hoặc làm cho kết luận ở câu sau càng rõ ràng hơn');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '何必 /Hébì/', 'Phó từ', 'Dùng ngữ khí phản vấn để biểu thị không cần thiết, không bắt buộc ("cần gì phải, hà tất").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '多亏 /Duōkuī/', 'Động từ', 'Do có sự giúp đỡ của người khác hoặc bởi vì một vài nhân tố có lợi, mà tránh được rủi ro hoặc đạt được lợi ích nào đó ("may nhờ, nhờ có").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '所谓 /Suǒwèi/', 'Tính từ', 'Biểu thị thường hay nói, dùng để đề ra từ ngữ cần giải thích ("cái gọi là"). Chỉ những điều do một vài người nói, thường biểu thị không đồng ý, không thừa nhận.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '则 /Zé/', 'Lượng từ/Liên từ', 'Lượng từ: Thường dùng với văn bản ngắn thành đoạn hoặc thành bài (mẩu tin, câu chuyện) Liên từ: Thường gặp kết cấu “A·····，（而）B 则······” biểu thị sự so sánh giữa câu trước và câu sau. Liên từ: Biểu thị mối quan hệ nhân quả (tương đương với “就” trong văn nói).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '为······所 ····· /Wéi... Suǒ../', 'Kết cấu cố định', 'Kết cấu cố định, thường dùng trong văn viết, trong đó “为” biểu thị ý nghĩa là “被” (bị/được).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '起 /Qǐ/', 'Động từ', 'Động từ (làm bổ ngữ), biểu thị sự liên tiếp, kết hợp và cố định.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '动词 + 过 (Guò)', 'Động từ xu hướng', 'Dùng với cách thức “động từ + 得/不 + 过” làm bổ ngữ, biểu thị ý nghĩa là quá, vượt qua, hơn (thường dùng trong so sánh năng lực, trình độ).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '迟早 /Chízǎo/', 'Phó từ', 'Biểu thị một vài động tác hoặc sự việc sớm muộn cũng sẽ xảy ra.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '再三 /Zàisān/', 'Phó từ', 'Có nghĩa là “hết lần này đến lần khác”, thường đi với động từ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '即 /Jí/', 'Động từ/Phó từ', 'Động từ: Dùng trong văn viết, nghĩa là “就是” (tức là). Phó từ: Có nghĩa là “就” “便” (thì, ngay).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '个别 /Gèbié/', 'Tính từ', 'Có nghĩa là “单个，各个” (từng cái, mỗi cái). Biểu thị cực kỳ ít, hiếm có.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '非 /Fēi/', 'Tiền tố/Động từ/Phó từ', 'Tiền tố: Đứng trước cụm danh từ, biểu thị là không thuộc về phạm vi này. Động từ: Có nghĩa là “不是” (không phải). Phó từ: Biểu thị chủ quan cố ý, kiên trì làm một việc gì đó (thường dùng trong cấu trúc “非+ động từ + 不可”).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '以 /Yǐ/', 'Giới từ/Liên từ', 'Giới từ: Có nghĩa là “用、拿、 凭借” (dùng, lấy, dựa vào, nhờ vào). Liên từ: Biểu thị mục đích ("để").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '平常 /Píngcháng /', 'Tính từ/Danh từ', 'Tính từ: Biểu thị phổ thông, bình thường, không có gì đặc biệt Danh từ: Ý nghĩa là “平时” (ngày thường, lúc thường).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '宁可 /Nìngkě/', 'Phó từ', 'Biểu thị sau khi so sánh, chọn lựa được 1 bên tương đối có lợi ("thà rằng... còn hơn").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '极其 /Jíqí/', 'Phó từ', 'Có nghĩa là “非常” (rất, cực kỳ), thường dùng trong văn viết, chỉ có thể bổ sung cho tính từ song âm tiết hoặc đa âm tiết.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '其余 /Qíyú/', 'Đại từ', 'Biểu thị phần còn lại, bộ phận khác.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '可见 /Kějiàn/', 'Liên từ', 'Thường dùng cách thức “······，（由此）可见······”, biểu thị có thể dựa vào tình huống được nói đến trong văn bản mà đưa ra phán đoán, đánh giá.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '般 /Bān/', 'Trợ từ', 'Có nghĩa là “一样” “似的” (tựa như, như), thường đứng sau danh từ, tạo thành một cụm từ làm định ngữ hoặc trạng ngữ.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '闻 (Wén)', 'Ngữ tố/Động từ', 'Ngữ tố: Có nghĩa là "nghe thấy hoặc tin tức, sự việc được nghe thấy"/ Động từ: Biểu thị dùng mũi để cảm nhận, nhận biết mùi vị.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '趁 /Chèn/', 'Giới từ', 'Có nghĩa là lợi dụng (thời gian, cơ hội).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '动词+得/ 不+起 (De/Bù Qǐ)', 'Kết cấu', 'Biểu thị về mặt chủ quan có (không có) năng lực và điều kiện thực hiện (hoặc tiếp nhận) động tác nào đó.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '支 /Zhī/', 'Động từ/Lượng từ', 'Động từ: Biểu thị dùng đồ vật chống cho vật thể không bị đổ xuống Lượng từ: Dùng trong tác phẩm âm nhạc, đội ngũ, hoặc đồ vật có hình cán (cây, bản).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '凭 /Píng/', 'Động từ/Giới từ', 'Động từ: Có nghĩa là nhờ vào, dựa vào. Giới từ: Biểu thị căn cứ, dựa vào (thường dùng cách thức “凭+ tân ngữ + động từ”).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '硬 /Yìng/', 'Phó từ', 'Biểu thị kiên quyết hoặc cố chấp làm một việc gì đó. Biểu thị không đủ năng lực nhưng vẫn tiếp tục tận lực để làm một việc gì đó ("cố gắng, cố chấp").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '偶然 /Ǒurán/', 'Tính từ/Phó từ', 'Tính từ: Biểu thị sự việc phát sinh ngoài dự đoán hoặc dựa vào quy luật thông thường thì không có khả năng phát sinh ("ngẫu nhiên, bất ngờ"). Phó từ: Có nghĩa là “偶尔，有 时候” (thỉnh thoảng/ có lúc).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '尽快 (Jǐnkuài)', 'Phó từ', 'Có nghĩa là nhanh hết mức có thể ("nhanh chóng").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '一旦 /Yīdàn/', 'Phó từ', 'Biểu thị thời gian không xác định, ngày đó bỗng nhiên tới hoặc giả dụ có ngày đó ("một khi").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '难免 /Nánmiǎn/', 'Tính từ', 'Có nghĩa là khó tránh khỏi, không thể tránh khỏi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '自从 /Zìcóng/', 'Giới từ', 'Biểu thị bắt đầu từ mốc thời gian nào đó trong quá khứ ("kể từ khi").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '一致 /Yīzhì/', 'Tính từ/Phó từ', 'Tính từ: Biểu thị không có sự chia rẽ, bất đồng. Phó từ: Biểu thị cùng nhau, đồng lòng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '某 /Mǒu/', 'Đại từ chỉ thị', 'Chỉ một người hoặc một vật nhất định (thường dùng sau họ, biểu thị biết tên nhưng không nói ra). Chỉ người hoặc vật không xác định.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '幸亏 /Xìngkuī/', 'Phó từ', 'Biểu thị do một vài nguyên nhân nào đó mà tránh được một số chuyện không hy vọng sẽ phát sinh ("may mà").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '行动 /Xíngdòng/', 'Động từ/Danh từ', 'Động từ: Biểu thị đi lại, hoạt động cơ thể. Cũng có thể biểu thị tiến hành hành động nào đó vì mục đích nào đó. Danh từ: Biểu thị hoạt động, hành vi.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '义务 /Yìwù/', 'Danh từ/Tính từ', 'Danh từ: Biểu thị trách nhiệm về mặt pháp luật, đạo đức nên gánh vác, đảm nhiệm ("nghĩa vụ"). Tính từ: Biểu thị không nhận thù lao (mang tính nghĩa vụ).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '朝 /Cháo/', 'Động từ/Giới từ', 'Động từ: Biểu thị hướng về, đối mặt Giới từ: Biểu thị phương hướng của hành vi, động tác đã chỉ');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '简直 /Jiǎnzhí/', 'Phó từ', 'Biểu thị gần như là vậy nhưng cũng không hẳn hoàn toàn là như vậy. Mang ngữ khí khoa trương, nhấn mạnh ("quả là/thật là").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '来 /Lái/', 'Trợ từ', 'Đứng sau các từ chỉ số “十、 百、千”... hoặc từ chỉ số lượng, biểu thị ước lượng ("khoảng hơn"). Dùng sau các từ chỉ số như “一、二、三” tạo thành kết cấu “一来······，二来······” biểu thị liệt kê lí do ("một là... hai là...").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '至于 /Zhìyú/', 'Động từ/Giới từ', 'Động từ: Biểu thị đạt đến một loại trình độ nào đó (thường dùng trong câu phản vấn với ý "đến mức"). Giới từ: Dùng trong kết cấu “（A）·····，至于（B）······” biểu thị nhắc đến một việc khác nữa ("còn về").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '总算 /Zǒngsuàn/', 'Phó từ', 'Biểu thị nguyện vọng cuối cùng cũng đã được thực hiện sau khi trải qua một khoảng thời gian dài ("cuối cùng cũng"). Biểu thị về mặt cơ bản vẫn vượt qua được ("dù sao cũng").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '下来 /Xiàlái/', 'Bổ ngữ xu hướng', 'Biểu thị hoàn thành (một hành động, một sự việc)');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '舍不得 /Shěbudé/', 'Động từ', 'Biểu thị không muốn từ bỏ, tiêu phí hoặc sử dụng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '从此 /Cóngcǐ/', 'Phó từ', 'Biểu thị từ thời điểm này hoặc từ thời điểm nói trở đi ("từ đó về sau").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '假设 /Jiǎshè/', 'Động từ/Danh từ', 'Động từ: Biểu thị coi một số tình huống là thật ("giả sử"). Danh từ: Biểu thị tình huống giả thiết, tưởng tượng ("giả thiết").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '堆 /Duī/', 'Lượng từ/Động từ/Danh từ', 'Lượng từ: Dùng cho đám người hoặc đống đồ vật. Động từ: Biểu thị dùng tay hoặc dụng cụ để xếp, chất lên nhau. Danh từ: Biểu thị đồ vật xếp cùng nhau.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '不如 /Bùrú/', 'Động từ', 'Biểu thị không thể sánh bằng.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '干脆 /Gāncuì/', 'Tính từ/Phó từ', 'Tính từ: Dứt khoát Phó từ: Biểu thị đơn giản, quyết đoán');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '万一 /Wànyī/', 'Liên từ/Danh từ', 'Liên từ: Biểu thị khả năng rất nhỏ, thường dùng với trường hợp không ngờ đến hoặc bất lợi Danh từ: Biểu thị tình huống bất ngờ có khả năng rất nhỏ (thường dùng trong cách thức cố định “就怕万一”).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '无意 /Wúyì/', 'Động từ', 'Động từ: Có nghĩa là không muốn, không có ý định..');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '有利 /Yǒulì/', 'Tính từ', 'Có nghĩa là có lợi, có ích (thường dùng “有利于” để biểu thị có lợi cho người hoặc vật nào đó).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '的确 /Díquè/', 'Phó từ', 'Ý nghĩa là hoàn toàn chính xác, chân thực ("quả thực, đích thực").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '嗯 (Ńg/Ǹg)', 'Thán từ', 'Biểu thị nghi vấn. Biểu thị đáp ứng hoặc chấp thuận.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '轻易 /Qīngyì/', 'Tính từ/Phó từ', 'Tính từ: đơn giản, dễ dàng Phó từ: Biểu thị thái độ khi xử lí công việc không cẩn thận, rất tùy tiện. Thường dùng trong câu phủ định (“轻 易不·····” nghĩa là “rất ít làm”).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '密切 /Mìqiè/', 'Tính từ/Động từ', 'Tính từ: Biểu thị quan hệ gần gũi, mật thiết. Động từ: Có nghĩa làm cho quan hệ trở nên gần gũi mật thiết hơn.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '尽量 /Jǐnliàng/', 'Phó từ', 'Biểu thị trong một phạm vi nhất định nỗ lực đạt đến mức độ cao nhất ("cố gắng hết sức").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '逐步 /Zhúbù/', 'Phó từ', 'Biểu thị từng bước từng bước một (thường dùng trong những tình huống do con người làm ra).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '照常 /Zhàochán g/', 'Động từ/Phó từ', 'Động từ: Có nghĩa là giống như bình thường Phó từ: Biểu thị tình huống tiếp tục không thay đổi ("như thường lệ").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '难怪 /Nánguài/', 'Động từ/Phó từ', 'Động từ: không nên phê bình, oán trách), mang ngữ khí thông cảm, tha thứ. Phó từ: Biểu thị đã rõ nguyên nhân, không còn cảm thấy lạ lùng với tình huống nào đó nữa ("thảo nào, hèn chi").');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '与其 /Yǔqí/', 'Liên từ', 'Dùng khi so sánh 2 tình huống cần phải lựa chọn, “与 其” sử dụng về mặt từ bỏ, đằng sau có thể kết hợp dùng');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '过 /Guò/', 'Bổ ngữ xu hướng', 'Biểu thị người hoặc vật thể thông qua động tác để thay đổi phương hướng hoặc di chuyển vị trí.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '开 /Kāi/', 'Bổ ngữ xu hướng', 'Biểu thị mở ra, giãn ra.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '赶快 /Gǎnkuài/', 'Phó từ', 'Ý nghĩa là bắt kịp thời gian, gia tăng tốc độ).');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '片 /Piàn/', 'Danh từ/Lượng từ', 'Danh từ: Đồ vật có bề mặt phẳng, mỏng, thường không quá lớn Lượng từ: Dùng để chỉ những đồ vật thành phiến, cũng có thể dùng với âm thanh, cảnh sắc.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '根本 /Gēnběn/', 'Danh từ/Tính từ/Phó từ', 'Danh từ: Bộ phận quan trọng nhất của sự vật. Tính từ: Ý nghĩa là “chủ yếu, quan trọng nhất” Phó từ: Biểu thị từ đầu đến cuối, trước sau như một');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '除非 /Chúfēi/', 'Liên từ/Giới từ', 'Liên từ: Biểu thị điều kiện duy nhất, giống với “只有”, đằng sau thường đi với “才、 否则、不然” ("trừ phi"). .Giới từ: ngoại trừ');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '直 /Zhí/', 'Phó từ', 'Dùng để diễn tả hành động diễn ra liên tục, không bị gián đoạn, thường đứng trước động từ đơn âm tiết.');
INSERT INTO grammar (level, title, explanation, examples) VALUES ('HSK 5', '反正 /Fǎnzhèng/', 'Phó từ', 'Biểu thị tình huống tuy không giống nhưng kết quả lại như nhau ("dù sao thì"). Biểu thị ngữ khí kiên quyết khẳng định.');